	$this->AddTable($package,'Facets',$col, array("Suit", "FacetInitial", "FacetName"), array(array('LocalCol'=>'Suit', 'Table'=>'Suits','ForCol'=>'Suits_Id')), array('Description'=>'The Omniverse is many-faceted, infact there are 24 of them, arranged in pairs','Tooltip'=>'A Facet', 'HelpText'=>'Everything in the Omniverse is made from one or a combination of Facets.', 'Code'=>'Open', 'ContainerPost'=>FALSE, 'DisplayRow'=>'<details class="facet" data-level="%level%" data-help="%tab-help%" data-tooltip="%tab-tooltip%" ><summary class="facet-initial">%FacetInitial%</summary><p><strong>Facet Name: </strong><span class="facet-name">%FacetName%</span><span class="facet-tao">%Yang%</span><span class="facet-suit">%Suit%</span><p><strong>Description: </strong><span class="suit-desc">%Description%</p></details>','Template'=>''), array(array('FacetInitial'=>'A', 'FacetName'=>'Awe', 'Yang'=>true, 'Description'=>'Awe is the Yang Facet of the sublime and the spirit, it governs emotions and emotional effects. From veneration, to dread, and wonderment to esteem. It is the Facet of Idols and has the emotional maturity to rise above the derision of its opposite of Jeer.', "Suit"=>1), 
		array('FacetInitial'=>'B', 'FacetName'=>'Burden', 'Yang'=>false, 'Description'=>'Burden is the Yin Facet of the material. Wealth and weight fall beneath Burden&#39;s corporeal control. It is the Facet of Elemental Earth, passive and receptive it governs the emotions of sadness and trust. It is the opposite of Gossamer.', "Suit"=>3), 
		array('FacetInitial'=>'C', 'FacetName'=>'Craft', 'Yang'=>true, 'Description'=>'Craft is the Yang Facet of artifice and creation. The Yang opposite of Nature it is the creator that builds, constructs and works.', "Suit"=>1), 
		array('FacetInitial'=>'D', 'FacetName'=>'Dominion', 'Yang'=>true, 'Description'=>'Dominion is the Yang Facet of control, groups, civilization, the body politic, the abilities to socialise and lead. It is an active facet that governs groups, areas and control and it is the opposite of Yonder.', "Suit"=>3), 
		array('FacetInitial'=>'E', 'FacetName'=>'Enigma', 'Yang'=>false, 'Description'=>'Enigma is the Facet of secrets, mysteries, hidden behaviours and cryptic things. Passive and Yin it is the occult opposite of Key.', "Suit"=>2), 
		array('FacetInitial'=>'F', 'FacetName'=>'Fury', 'Yang'=>true, 'Description'=>'Fury is the Yang Facet of anger and deep emotional intensity. It is the unbridled storm tossed sea an the thundering waterfall, all the active dynamic forces are in some way, some of the time governed by its certainty. It&#39;s opposite is the Yin facet Quiet.', "Suit"=>3), 
		array('FacetInitial'=>'G', 'FacetName'=>'Gossamer', 'Yang'=>true, 'Description'=>'Gossamer is the dynamic Yang Facet of strength without weight. Silken threads drifting in the wind, the forces that bend and shake trees and can rip and tear flesh. Gossamer is the light, airy opposite of Burden.', "Suit"=>4), 
		array('FacetInitial'=>'H', 'FacetName'=>'Heresy', 'Yang'=>true, 'Description'=>'Heresy is the Yang Facet of lies, deceit, fiction and those things believed to be false. It is the governor of error, the ancestor of dissent and the blame for impiety. It is the dynamic opposite of Orthodox.', "Suit"=>2), 
		array('FacetInitial'=>'I', 'FacetName'=>'Inertia', 'Yang'=>false, 'Description'=>'Inertia is the Yin Facet of motion, inexorable momentum, falling and sliding. The mother of indolence and lassitude, the patron of procrastination this receptive facet will out-wait and out-last its opposite Zeal.', "Suit"=>4),
		array('FacetInitial'=>'J', 'FacetName'=>'Jeer', 'Yang'=>false, 'Description'=>'Jeer is the Yin Facet of emotions. It is the chuckling king of fools, the master of mimicry and mockery, the home of humour and is of course the joke behind its opposite Awe.', "Suit"=>2), 
		array('FacetInitial'=>'K', 'FacetName'=>'Key', 'Yang'=>true, 'Description'=>'Key is the Yang Facet of solutions, answers, ingress and interpretation. It is the patron of perception and penetration, the source of science and the &#39;key&#39; to the cipher of its opposite Enigma.', "Suit"=>4),  
		array('FacetInitial'=>'L', 'FacetName'=>'Liberty', 'Yang'=>true, 'Description'=>'Liberty is the Yang Facet of freedom. It is the dream that is imagined, and the imagination itself, the freedom to dream, the license to leisure, the choice of chance, the autocrat of luck and the flexibility and flux to deny its opposite Wyrd.', "Suit"=>2),  
		array('FacetInitial'=>'M', 'FacetName'=>'Miasma', 'Yang'=>false, 'Description'=>'Miasma is the Yin Facet of corruption and rotting. It is the foulness within, the stink without, it is the dark haze that hides the blight of contamination. So foul is the Facet that its stench may even survive the purifying fire of Phoenix', "Suit"=>3),  
		array('FacetInitial'=>'N', 'FacetName'=>'Nature', 'Yang'=>false, 'Description'=>'Nature is the Yin Facet of the receptive and nurturing mother of us all. Passive growth, fertility and flesh are all aspects of this Facet. Nature governs all things native, and genuine unlike the artifice of its opposite Craft.', "Suit"=>2),  
		array('FacetInitial'=>'O', 'FacetName'=>'Orthodox', 'Yang'=>false, 'Description'=>'Orthodox is the Yin Facet of truth. Orthodox is passive data, a simple truth stood in plain sight, it is approved knowledge, confirmed and conventional. It is the latent law, ever present, plain and proper and only occasionally is it stirred into reactionary activity by its opposite Heresy.', "Suit"=>1),  
		array('FacetInitial'=>'P', 'FacetName'=>'Phoenix', 'Yang'=>true, 'Description'=>'Phoenix is the Yang Facet of Elemental Fire. Transcendent the Facet is not just the father of the physical flame, but also the fires within, it is the purveyor of passions and the root of regeneration, its process powers all life and even the stars. Unchecked it can burn and fry all things including its opposite Miasma.', "Suit"=>2),  
		array('FacetInitial'=>'Q', 'FacetName'=>'Quiet', 'Yang'=>false, 'Description'=>'Quiet is the Yin Facet of receptive silence. In that silence rest quiescent woods, tranquil trees, hushed leaves and even the silent speech of books and plain libraries (and mute, conservative librarians). Sober, calm and studied Quiet is the only way to soothe its opposite Fury.', "Suit"=>1),  
		array('FacetInitial'=>'R', 'FacetName'=>'Rook', 'Yang'=>false, 'Description'=>'Rook is the Yin Facet of defence. Receptive and resilient it is the bastion of the Facets. Armour and Aegis, shielding and protective it is the only true guard against its opposite Trial.', "Suit"=>3),  
		array('FacetInitial'=>'S', 'FacetName'=>'Sin', 'Yang'=>true, 'Description'=>'Sin is the Yang Facet of vices. It is the source of all evil, the inception of immorality, the well of wickedness and is the Facet of transgression and trespass and the one weakness of its opposite Virtue.', "Suit"=>3),  
		array('FacetInitial'=>'T', 'FacetName'=>'Trial', 'Yang'=>true, 'Description'=>'Trial is the Yang Facet of competition. It is the commencement of hostilities, the cause of war and the source of sports. Whether striving at tournament or struggling to win Trial is continually in conflict with its opposite Rook.', "Suit"=>4),  
		array('FacetInitial'=>'V', 'FacetName'=>'Virtue', 'Yang'=>false, 'Description'=>'Virtue is the Yin Facet that governs Goodness. The Facet is the home of hope, love and charity. Incorruptible and innocent it is the Facet of worth and worthiness and the only Facet that the compassion to embrace its opposite Sin.', "Suit"=>1),  
		array('FacetInitial'=>'W', 'FacetName'=>'Wyrd', 'Yang'=>false, 'Description'=>'Wyrd is the Yin Facet of the goddess of destiny. Binding and weaving she envelops everything in her nets of karma, kismet and doom. Her&#39;s is the Facet of inevitability, predestination, misfortune and providence, the only Facet able to plan for and predict its opposite Liberty.', "Suit"=>3),  
		array('FacetInitial'=>'Y', 'FacetName'=>'Yonder', 'Yang'=>false, 'Description'=>'Yonder is the Yin Facet of space and distance. Completely passively this Facet sits holding point A apart from point B. The decider of distance and the root of range and roads, the Facet oversees all paths from space-lanes to highways to the Lea. Passive and inert Yonder lies always beyond the control but able to reach the heart of its opposite Dominion', "Suit"=>4),  
		array('FacetInitial'=>'Z', 'FacetName'=>'Zeal', 'Yang'=>true, 'Description'=>'Zeal is the Yang Facet of dynamic motion. It is the dominant, active force that drives enthusiasm, ambition and desire. Earnest and eager it is fervour of fanaticism, faith and confidence of belief. Zeal is the only capable of kicking into action its opposite of Inertia.', "Suit"=>1) ) );
//---------------------------------------------Boons------------------------------------------------
	$col=array();
	$col[]=array('Name'=>'Draw', 'Type'=>'INTEGER', 'Edit'=>'<input type="number" value="%d" min="0" />', 'Display'=>'<span>', 'CSS'=>'draw', 'Tooltip'=>'How many cards the Boon would draw in an ordeal (based on an average roll)');
		$col[]=array('Name'=>'Score', 'Type'=>'DECIMAL(10,1)', 'Edit'=>'<input type="number" value="%f" min="0" />', 'Display'=>'<span>', 'CSS'=>'red', 'Tooltip'=>'The average Score of this Boon&#39;s dice rolls');
		$col[]=array('Name'=>'Boon', 'Type'=>'INTEGER', 'Edit'=>'<input type="number" value="%d" min="1" />', 'Display'=>'<span>', 'CSS'=>'boon', 'Tooltip'=>'A Boon is the base number we use in the system.');
		$col[]=array('Name'=>'Value', 'Type'=>'BIGINT', 'Edit'=>'<input type="number" value="%d" min="1" />', 'Display'=>'<span>', 'CSS'=>'value', 'Tooltip'=>'A "Real-World" Value that is used in calculations of Annex Boons, etc.');
		$this->AddTable($package,'Boons',$col, array('Score', 'Boon', 'Value'), '', array('Description'=>'The Boon Table is used for converting Values to Boons, Boons to Scores, and Scores into Card Draws.','Tooltip'=>'REALLY DO NOT EDIT!', 'HelpText'=>'Boons are the stats of T13. Most Characters have an average 13 Boon across the Omniverse.', 'Code'=>'Open', 'ContainerPost'=>FALSE, 'DisplayRow'=>'<details data-level="%level%" data-help="%tab-help%" data-tooltip="%tab-tooltip%" ><summary><span class="boon">%Boon%</span></summary>
		<table class="boon-table"><thead><tr><td>Draw</td><td>Score</td><td>Boon</td><td>Value</td></tr></thead><tbody><tr><td class="draw">%Draw%<td class="red">%Score%</td><td class="boon">%Boon%</td><td class="value">%Value%</td></tr></tbody></table></details>','Template'=>''));
		for ($i=0;$i<10;$i++){
			$this->addBoonRow();
		}
//------------------------Personality-Facet-Core------------------------------------
	$retvar = array('message'=>'Core Facets Loaded', 'package'=>(int)$package++);
	break;
	case 5:
	$col=array();
	$col[]=array('Name'=>'Attack', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" maxlength="32" value="%s" />', 'Display'=>'<span>','CSS'=>'attack-name', 'Tooltip'=>'Facet Attack');
	$col[]=array('Name'=>'Attack_Text', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'attack-text', 'Tooltip'=>'How does this Facet attack?');
	$col[]=array('Name'=>'Core', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" maxlength="32" value="%s" />', 'Display'=>'<span>','CSS'=>'core-name', 'Tooltip'=>'Facet Core');
	$col[]=array('Name'=>'Core_Text', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'core-text', 'Tooltip'=>'What is the Special Rule this Core confers?');
	$col[]=array('Name'=>'Handicap', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" maxlength="32" value="%s" />', 'Display'=>'<span>','CSS'=>'handicap-name', 'Tooltip'=>'Facet Handicap');
	$col[]=array('Name'=>'Handicap_Text', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'handicap-text', 'Tooltip'=>'What is this Handicap like?');
	$col[]=array('Name'=>'Incarna', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" maxlength="32" value="%s" />', 'Display'=>'<span>','CSS'=>'incarna-name', 'Tooltip'=>'Facet Incarna');
	$col[]=array('Name'=>'Incarna_Text', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'incarna-text', 'Tooltip'=>'What is made of this Incarna?');
	$col[]=array('Name'=>'Monster', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" maxlength="32" value="%s" />', 'Display'=>'<span>','CSS'=>'monster-name', 'Tooltip'=>'Facet Monster');
	$col[]=array('Name'=>'Monster_Text', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'monster-text', 'Tooltip'=>'What does this Monster do?');
	$col[]=array('Name'=>'Personality', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" maxlength="32" value="%s" />', 'Display'=>'<span>','CSS'=>'personality-name', 'Tooltip'=>'Facet Personality');
	$col[]=array('Name'=>'Personality_Text', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'personality-text', 'Tooltip'=>'How does this Personality gain Chi?');
	$col[]=array('Name'=>'Quest', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" maxlength="32" value="%s" />', 'Display'=>'<span>','CSS'=>'quest-name', 'Tooltip'=>'Facet Quest');
	$col[]=array('Name'=>'Quest_Text', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'quest-text', 'Tooltip'=>'What does the Quest entail?');
	$col[]=array('Name'=>'Tone', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" maxlength="32" value="%s" />', 'Display'=>'<span>','CSS'=>'tone-name', 'Tooltip'=>'Facet Tone');
	$col[]=array('Name'=>'Tone_Text', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'tone-text', 'Tooltip'=>'What is this Tone like?');
	$this->AddTable($package,"CharacterFacets",$col, array('Attack', 'Core', 'Handicap', 'Incarna', 'Personality', 'Quest', 'Tone'), array(array('LocalCol'=>'CharacterFacets_Id', 'Table'=>'Facets','ForCol'=>'Facets_Id')), array('Description'=>'This extends the Facets, adding all manner of Character and Descendant notes','Tooltip'=>'A Facet', 'HelpText'=>'Everything in the Omniverse is made from one or a combination of Facets.', 'Code'=>'Extend', 'ContainerPost'=>FALSE, 'DisplayRow'=>'<details data-level="%level%" data-help="%tab-help%" data-tooltip="%tab-tooltip%" ><summary><strong>Facet Character Features<strong></summary><details class="facet-details"><summary class="facet-attack"><strong>Attack: </strong><span class="attack-name">%Attack%</summary><p class="attack-text">%Attack_Text%</p></details><details class="facet-details"><summary class="facet-core"><strong>Core: </strong><span class="core-name">%Core%</summary><p class="core-text">%Core_Text%</p></details><details class="facet-details"><summary  class="facet-handicap"><strong>Handicap: </strong><span class="handicap-name">%Handicap%</summary><p class="handicap-text">%Handicap_Text%</p></details><details class="facet-details"><summary class="facet-incarna"><strong>Incarna</strong><span class="incarna-name">%Incarna%</summary><p class="incarna-text">%Incarna_Text%</p></details><details class="facet-details"><summary class="facet-monster"><strong>Monster: </strong><span class="monster-name">%Monster%</summary><p class="monster-text">%Monster_Text%</p></details><details class="facet-details"><summary class="facet-personality"><strong>Personality: </strong><span class="personality-name">%Personality%</summary><p class="personality-text">%Personality_Text%</p></details><details class="facet-details"><summary class="facet-quest"><strong>Quest: </strong><span class="quest-name">%Quest%</summary><p class="quest-text">%Quest_Text%</p></details><details class="facet-details"><summary class="facet-tone"><strong>Tone: </strong><span class="tone-name">%Tone%</summary><p class="tone-text">%Tone_Text%</p></details></details>','Template'=>''), array(
		array('Attack'=>'Duck', 'Attack_Text'=>'Duck attacks force the defender to duck and dive for cover. Duck attacks are often the result of Fear based attacks. Duck attacks cause double damage (x2) when causing Distract or Flesh wounds.', 'Core'=>'Enhancer', 'Core_Text'=>'The Character may choose one Nimbed effect and add it to any Annex for an activation cost of that Facet&#39;s Boon Reduced x2 Sway (Boon Reduced Chi).', 'Handicap'=>'Fear', 'Handicap_Text'=>'Either suffering from (as on a phobia), or causing Fear', 'Incarna'=>'Spirit (Ka)', 'Incarna_Text'=>'As Awe is the Facet of Spirit its Incarna is Spirit. The Ka is the living soul that leaves the body upon death in the ancient religion of Egypt and echoes of this belief are found within most religions. Pick this Facet Incarna if you are wanting to play a ghost or nature spirit, or perhaps a Djinn or Familiar.', 'Monster'=>'Terror', 'Monster_Text'=>'The Monster is a Fear or Anxiety embodied. They are quite diverse in form but are always able to cause Psychology Test attacks such as Fear, Terror or Horror.','Personality'=>'Idol', 'Personality_Text'=>'<p>Gain Chi when you are respected, honoured, worshipped or adored – you have someone&#39;s undivided attention, or answer a question. </p><p>Combat gain Chi when you play a &diams; to attack a target.</p>', 'Quest'=>'Brave / Charm', 'Quest_Text'=>'The Quest may send the adventurers to a dangerous location, or to face a terrible monster or object, or instead they may simply have to charm an old woman they meet upon the way so that she will tell the secret of soothing the beast. Or perhaps they have to persuade their new boss to send them on that new job. The point is that the character on the Quest will have to use their Awe Facet to the best of their ability.', 'Tone'=>'Emotional', 'Tone_Text'=>'Any story that has an Awe Tone is going to be emotional. Whether its the heart-breaking plight of a boy and his dog, or a cancer-ridden mother trying to do the best for her children before she dies, this is the Tone of sad stories that are low on action, but high in characterisation.' ), 
		array('Attack'=>'Pound', 'Attack_Text'=>'Pound attacks are crushing and pulverizing, they rarely break the skin instead breaking bones more often. Pound attacks do triple damage (x3) when causing Maiming wounds.', 'Core'=>'Wielder', 'Core_Text'=>'When the character is holding/wearing or using a specific descendant/trophy/monolith/artefact add a success level.', 'Handicap'=>'Vulnerable', 'Handicap_Text'=>'Perhaps they are flammable or easily startled, they might have an allergy, or similar weakness.', 'Incarna'=>'Earth', 'Incarna_Text'=>'Burden is the Incarna Facet to choose if you wish to build a statue, or play a living rock. Gemstones, Earth Elementals (Gnomes) and buildings can also share this Incarna.','Monster'=>'Object', 'Monster_Text'=>'The Monster is an object imbued with the semblance of life. Artificial in nature usually, the living object is tough and strong, able to double scores when appropriate for their form.', 'Personality'=>'Reaper', 'Personality_Text'=>'<p>Gain Chi when you make a material gain, take or accept something, or ask for more.</p><p>Combat gain Chi when you draw a &clubs; in combat</p>', 'Quest'=>'Obtain', 'Quest_Text'=>'This quest would have the characters try to get, gather or acquire a specific or type of location, character or object.', 'Tone'=>'Dark', 'Tone_Text'=>'A story that is dark in Tone is a down-beat tale, often creepy, sinister or morbid.' ), 
		array('Attack'=>'Crash', 'Attack_Text'=>'Crash attacks affect vehicles and equipment, people generally have to be hit by a vehicle or be in a vehicle to suffer a crash attack. Technology and vehicle Descendants and Characters receive triple as many wounds from Crash attacks (x3).', 'Core'=>'Crafter', 'Core_Text'=>'Add Craft Boon Reduced to all Skill Annex rolls and all Item Creation Ordeal cards.', 'Handicap'=>'Impoverished', 'Handicap_Text'=>'Poor, disenfranchised or missing something in some way', 'Incarna'=>'Toil', 'Incarna_Text'=>'High craft of prolonged time. Craft is the Incarna to pick if you wish to play or build a carefully constructed, fiddly mechanical thing. You might want a robot or mechanimal to be made from Toil, many works of art are actually made from Craft.', 'Monster'=>'Maker', 'Monster_Text'=>'The Monster is actually a creator of other Monsters. The spawn are often less powerful than the creator, but in some cases are unique and more powerful. The creator may not be directly encountered until late in the Story.', 'Personality'=>'Smith', 'Personality_Text'=>'<p>Gain Chi when you create something (a descendant - prop or location), use an object (prop/monolith/artefact) you have created or give another character a creation.</p><p>Combat gain Chi when you use a Descendant you have created in combat.</p>', 'Quest'=>'Build / Work', 'Quest_Text'=>'When the Ref wants the characters to create something or work for somebody this is the Quest to use.', 'Tone'=>'Creative', 'Tone_Text'=>'A Creative Tone is common in stories about art. If the story is about production, creation of an item then you may want to use a Creative Tone.' ), 
		array('Attack'=>'Explode', 'Attack_Text'=>'Explode attacks do exactly that. They cause the target to partially or completely explode. The Explode wound will multiply itself to affect a number of additional Targets equal to the total Wound Class +1 (see Ordeal Cards) however all Range costs apply from the original Target as Braced firing, so the damage reduces with distance from the centre. You may still add additional targets with a +3 to Difficulty for each target.', 'Core'=>'Dominator', 'Core_Text'=>'Gain Chi when you give orders, exert authority or power.', 'Handicap'=>'Madness', 'Handicap_Text'=>'Mental disabilities, injuries and illnesses, or just plain barking.', 'Incarna'=>'Group', 'Incarna_Text'=>'When you want to play or build a society or social construct (such as a Pact, a Guild, a Company or even a family), or if you wish to play a social insect hive (or a Vermis Bulmäs) then you want a Dominion Incarna.', 'Monster'=>'Horde', 'Monster_Text'=>'The Monster is a group or swarm of lesser monsters, it might be an Army, a pack of Bulmäs, a Fortress or a Battle Moon.', 'Personality'=>'Leader', 'Personality_Text'=>'<p>Gain Chi when your orders are followed, you make suggestions, ask questions, or you succeed alone.</p><p>Combat gain Chi when you play any card on or for an ally.</p>', 'Quest'=>'Control / Lead / Join', 'Quest_Text'=>'If the Ref wants the players to keep control of something, to lead an army or join a guild that&#39;s a Dominion Quest.', 'Tone'=>'Political', 'Tone_Text'=>'Dense plots about people and societies fill this Tone. The Political Tone is often about shady backroom deals, subtle maneuverings, secrets and private vendettas.' ), 
		array('Attack'=>'Ambush','Attack_Text'=>'Ambushes (or blindsides) are attacks designed to surprise and shock the enemy. Ambushes double the damage (x2) of any Distract or Flesh wounds that they manage to land.','Core'=>'Significator','Core_Text'=>'May choose any one Wyrd Tarot card as a significator and may play any card, calling it their significator by paying the Face value of the significator in Sway. E.g. Fay can play a two of spades and call it a “Spot Hidden” by paying 7 points of Chi.','Handicap'=>'Vague', 'Handicap_Text'=>'Maybe its their unintelligible accent, or maybe they stammer, stutter, or just won&#39;t get to the point','Incarna'=>'Riddle','Incarna_Text'=>'If you are trying to create a code, or a puzzle, or if you are wanting to play a enigmatic creature of unknown origin then Enigma is the Incarna for you.','Monster'=>'Skulker','Monster_Text'=>'The Monster is a shadowy figure pulling strings behind the scenes. This may just be an ordinary villain, but their ability to pass unnoticed should be bordering upon the unnatural. Perhaps they use psychic powers or magic to pass unnoticed, perhaps they are a hacking whiz, able to bounce phone calls through international relays with some multinational or another picking up the tab without realizing, perhaps they are one of the Huldra, the hidden people - who may be the Fæ or maybe they are actually the imaginary friend of one of the characters now made real(ish) by an alien or a Dæmon.','Personality'=>'Sphinx','Personality_Text'=>'<p>Gain Chi when you confuse another or pose a question.</p><p>Combat gain Chi when you play any Distract card.</p>', 'Quest'=>'Hide','Quest_Text'=>'If the plot requires something to be hidden by the Characters then the Ref will be wanting an Enigma Quest.','Tone'=>'Mystery','Tone_Text'=>'Perhaps a murderer is afoot, or perhaps there is a deeper mystery abroad. Things are mysterious, evidence doesn&#39;t add up, or is missing altogether, perhaps the mystery is who the corpse is or how they got to the top of the mountain in scuba gear... this is not an average police procedural.'),
		array('Attack'=>'Bedlam','Attack_Text'=>'Bedlam attacks affect the mind of the target, they can be used to represent terror/horror attacks, shell shock and direct mental blasts as well as prolonged contact with Madness. Bedlam attacks do double damage (x2) against Inspiration, Dreams and Lie Incarna and double (x2) Distract Wounds.','Core'=>'Aggressor','Core_Text'=>'Gain Chi when you lose your temper, shout, or argue.','Handicap'=>'Lament', 'Handicap_Text'=>'When somehting has been lost, or forgotten, or you never had what everyone else has. It is the Handicap of Orphans and Widows, of Lost Loves and Haunting Memories','Incarna'=>'Water','Incarna_Text'=>'All liquids are descended from or are siblings of Elemental Water. Ever changing and unpredictable it is a very suitable Incarna for any liquids, potions or water nymphs, sirens or undines.','Monster'=>'Temperamental','Monster_Text'=> 'The Monster is the embodiment of an Emotion, usually a negative one. Such Monsters are often capable of supernatural actions, such as telepathy, shape-shifting, or even undying. The Vampire is an embodiment of Lust, with powers of mind control, telepathy and suggestion, as well as shapeshifting abilities. The Werewolf is berserk rage, and almost indestructible unless Silver is used. The Beansidhe is the embodiment of mourning, and able to sense an oncoming death.','Personality'=>'Beast','Personality_Text'=>'<p>Gain Chi when you are honest, blunt, direct or act quickly.</p><p>Combat gain Chi when you play a &clubs; to attack</p>','Quest'=>'Destroy','Quest_Text'=>'If the plot involves throwing a ring in a Volcano, blowing up an orbital fortress or laying to rest a powerful Necromancer then Fury is the Quest you want.','Tone'=>'Action','Tone_Text'=>'Whether its diving through plate glass, car chases, shoot outs, punch-ups, dangling over precipices or just buckling that swash action is about movement, quickly rising body counts and danger. Action Tone is low in Tension, being more about explosions and set pieces than tactical combat, but it can get gritty and real as well.'),
		array('Attack'=>'Rip','Attack_Text'=>'Rip attacks are the types of attacks made by strong powerful forces, like a bear’s claws. Maiming and Crippling attacks created by a Rip attack are doubled (x2).','Core'=>'Poser','Core_Text'=>'Gain Chi whenever you recite your catchphrase or strike a dramatic pose.','Handicap'=>'Malformed', 'Handicap_Text'=>'Mutations, missing limbs, or just plain ugly.','Incarna'=>'Air','Incarna_Text'=>'Not just Elemental Air, but any gas uses this Incarna. Need to build a gaseous weapon, or want to play a Sylph? Then Gossamer is the Incarna for you.','Monster'=>'Wiry','Monster_Text'=>'The Monster is immensely physically powerful, although often its form may not reveal it. It often demonstrates supernatural power as well as strength and toughness. Such monsters are often immune to Mortal Wounds always able to slink off instead of dying. A small, strong Goblin, a robot that looks like a little girl, a cybernetically enhanced rat, or even a killer doll are all examples of a Gossamer Monster','Personality'=>'Hero','Personality_Text'=>'<p>Gain Chi when being defeated, you disagree, or follow orders. </p><p>Combat gain Chi when attacked with a &spades;</p>','Quest'=>'Hold','Quest_Text'=>'Remember the Alamo? Helmsdeep? Well these are examples of the Gossamer Quest, so is any Quest to keep a Character prisoner or perhaps keep hold of a treasure.','Tone'=>'Conversational','Tone_Text'=>'Whether its a bunch of off-duty army doctors playing cards, men or women in the barbershop or beauty parlour there&#39;s plenty to like about the Conversational tone of the Gossamer Facet. You can tell whole stories and examine deep into a conflict with nothing more than a conversation.'),
		array('Attack'=>'Malign', 'Attack_Text'=>'Malign attacks are not physical in nature, they destroy the perceived character of the target. They can be considered as simple as name-calling, can be complex witty and cruel, or can be a targeted destruction of their character in the press. Distract wounds created by Malign attacks are Tripled (x3).', 'Core'=>'Pretender', 'Core_Text'=>'Character may choose a second personality and gain Chi from it also. Characters may change this second personality for Heresy Boon Reduced points of Chi.', 'Handicap'=>'Taboo', 'Handicap_Text'=> 'Whether religious, superstitious or just dietry, Taboos are things your character just doesn&#39;t want to do', 'Incarna'=>'Fiction', 'Incarna_Text'=>'Whether you are constructed a delicately balanced web of deceit, writing a pulp sci-fi ebook, or want to play an escaped fictional character on the run in the real world then Heresy is the Incarna Facet for you.', 'Monster'=>'Masker', 'Monster_Text'=>'The Monster is looks entirely like something else. Perhaps they are a Demon in the form of an innocent child, or maybe they are a shape-shifter or face-dancer, able to change their appearance as they like, then again perhaps they&#39;re just the old Janitor in a monster costume.', 'Personality'=>'Deviant', 'Personality_Text'=>'<p>Gain Chi when your actions are unique, or you lie, cheat, or mislead another – or deviate from normal behaviour. </p><p>Combat gain Chi when you play a &hearts; to attack.</p>', 'Quest'=>'Infiltrate / Lie ', 'Quest_Text'=>'If characters must infiltrate a secret society of enemy town, or spread disinformation, lies or propaganda then Heresy is probably the Quest they are using.', 'Tone'=>'Fantasy', 'Tone_Text'=>'Whether we are talking about fighting dragons in lonely mountain caves, facing ten thousands orcs from a fortress wall, creeping through the secret passageways of a wizard&#39;s tower or disarming megalithic dead-fall traps created by long-lost inhuman civilizations then you might be playing in a Fantasy Tone.'), 
		array('Attack'=>'Slash', 'Attack_Text'=>'Slash attacks are the classic Wound Dæmon. Teeth, claws, and knives cause them, a deep scratch that bleeds and can include cut muscle tissue. Slash wounds triple the number of Flesh wounds caused (x3).','Core'=>'Worker','Core_Text'=>'If the character takes their time they will automatically completely succeed (cannot be used during combat.) for a cost of one Chi.','Handicap'=>'Duty', 'Handicap_Text'=>'Whether its a duty to family, the law, or king and Country, some people are just driven by something greater than themselves.','Incarna'=>'Time','Incarna_Text'=>'If you want to manipulate time creating a save-point Chronolith event, or play a being that is a living moment then you will be wanting an Inertia Incarna.','Monster'=>'Unstoppable','Monster_Text'=>'The Monster is inexorable, it does not stop and cannot be killed by any normal means. Inertial Monsters are immune to Mortal and Carnage wounds until stacked out. They do not gain additional Handicaps. Examples of the Inertial Monster type include the Inexorable Zombies and all robotic assassins from the future.','Personality'=>'Sloth','Personality_Text'=>'<p>Gain Chi when you succeed without paying any cost, get someone else to do it, or have a rest.</p><p>Combat gain Chi when you draw a &spades.</p>','Quest'=>'Survive','Quest_Text'=>'Whether Location, Descendant, Character, Monster or a Trial, when winning is not an option sometimes the Quest just becomes about survival, whether its surviving on a desert island, not being blown up by a mine-field, not getting killed by a rival gang, or surviving a rite of passage then you might be in an Inertia Quest.','Tone'=>'Epic','Tone_Text'=>'When a story occasionally has to skip months, years or generations of time, or if the plot is of world shattering importance then you might be involved in an Inertia Tone Epic'),
		array('Attack'=>'Freeze','Attack_Text'=>'Freeze attacks can consist of Cold or more likely simply causing people to stand confused and ineffectually. Freeze attacks can result from a Fear/Terror/ Horror test or from cold based attacks. Distract and Flesh wounds caused by Freeze attacks are doubled (x2).','Core'=>'Joker','Core_Text'=>'Gain Chi and +1 success level when another nearby laughs.','Handicap'=>'Exposed', 'Handicap_Text'=>'Perhaps they are obvious, too distinctive, smelly, or brightly coloured, or maybe they are wanted by the police. Either way they attract more attention than normal because of this Handicap.','Incarna'=>'Illusion','Incarna_Text'=>'Whether you want to create an illusionary wall, a hologram, or if you want to play a Toon, hallucination or a mockery of human life risen from the grave then the Jeer Incarna is for you.','Monster'=>'Mockery','Monster_Text'=>'The monster is a mockery - usually a corpse animated by a low-level Increated to create Undead, but it may be a ghost, a machine or even an animal that mocks something else. The monster may even be a hallucination.','Personality'=>'Mimic','Personality_Text'=>'<p>Gain Chi when they copy another’s actions, are mistaken for what they mimic, or make a copy of an item.</p><p>Combat gain Chi when you play the same suit or wound class of card as the last card played.</p>','Quest'=>'Copy','Quest_Text'=>'Whether the Ref sees the plot as trying to duplicate a particular object or location or perhaps a character, or if the players will just be plagued by kids playing &#39;copycat&#39; then you want a Jeer Quest','Tone'=>'Comedy','Tone_Text'=>'Comedies come in many types, from the classical confusion based comedy, the comedy of manners through to gross-out comedies of the modern age. The only thing that unites them all is that it is meant to be funny. There may be witty banter, spoof scenarios or just general tomfoolery but it is all Jeer Tone.'),
		array('Attack'=>'Jab', 'Attack_Text'=>'Jab attacks are a standard of punches and quick stabs. Most bayonet wounds are Jab type; bullets also generally leave a Jab wound behind too. Jab attacks are particularly helpful against creatures that bleed (Flesh Incarna) and double Mortal Wounds (x2).','Core'=>'Sensor','Core_Text'=>'The character has an extra sense, often a danger sense or sixth sense. This is built as a free annex based on the Key Facet Boon (1-11 Skill, 12-21 Talent, 22-26 Power).','Handicap'=>'Confined', 'Handicap_Text'=>'When imprisioned, bound, held, confined, locked up, unable to cross running water, you can handle all that with a Key Handicap.','Incarna'=>'Inspiration','Incarna_Text'=>'If you want to build a meme, a memory, a thought, or play a being composed of pure thought then Key is the Incarna for you.','Monster'=>'Hunter','Monster_Text'=>'The Monster is a hunter or tracker, it should favour harrying attacks and hit and run tactics. Typically such a Monster will vanish or flee if it is wounded, only to reappear when healed. The hunter may be fooled by false trails, but never for long. Hunters are usually immune to Carnage and Mortal Wounds until the Zenith of the story (such wounds are taken as Crippling Wounds instead). In T13, the archetypal version of this Monster is a Bulmäs Pack member from the Wild Hunt, but any Werewolf or Animal Shifter would probably qualify, as would robot cowboys in theme parks that have gone wrong, and any Elven ranger','Personality'=>'Sleuth','Personality_Text'=>'<p>Gain Chi when you ask or answer a question, look for clues, or penetrate defences.</p><p>Combat gain Chi when you play a &spades; to prepare</p>','Quest'=>'Investigate/Seek','Quest_Text'=>'If the adventure involves trying to find information about someone or something or trying to locate a place, person or thing then you probably have a Key Quest.','Tone'=>'Investigative','Tone_Text'=>'When a story is about clues, and puzzles that can be solved, whether it be a police procedural, scientific investigation, or a gung-ho reporter, the Tone is Investigative and the Facet is Key.'),
		array('Attack'=>'Overload','Attack_Text'=>'Overload attacks like crash attacks work best on equipment, however Overload attacks work best on delicate electrical equipment and senses. Distract wounds are doubled (x2) for Overloads and Maiming and Crippling wounds target sensory proficiencies and Annexes.','Core'=>'Prevailer','Core_Text'=>'Ignore a Handicap when triggered by paying Sway equal to the half the normal reward.','Handicap'=>'Devotion', 'Handicap_Text'=>'What some people do from duty others do from Devotion. The power of True Love can bend people to its needs again and again, whether it be Romatic, Familial or Religious in nature, this is the Handicap for those who Love.','Incarna'=>'Dream','Incarna_Text'=>'If you wish to create a nightmare, or want to play a creature composed entirely of dreams, as some of the Fey are, then you want a Liberty Formation Facet','Monster'=>'Nightmare','Monster_Text'=>'The Monster is nightmarish, or dreamlike. Such Monsters either exist in a purely psychological realm, appearing as dreams and hallucinations, that cannot really be fought and don’t physically exist, or they are extremely dangerous and powerful Monsters that really exist and always cause Psychological Tests in those that meet them, and may be magical or supernatural in power. Flower-faced Humanoids and Canines from a nightmare realm, handsome soap-sellers with an odd idea for gentlemen’s clubs, facially-burned, gardening-gloved janitors turned serial killers, six foot tall invisible rabbits, night hags, shadow beings seen when falling asleep, and any character in a dream, are all good examples of the Liberty Monster.','Personality'=>'Rake','Personality_Text'=>'<p>Gain Chi when you try to be stylish, sensual, seductive, arrogant or rude. </p><p>Combat gain Chi when you prepare a &hearts;</p>','Quest'=>'Liberate','Quest_Text'=>'When a Ref wants you to take something from someone else, or if you want to mount a prison break, rescue a princess, or release an entire kingdom from a tyrant&#39;s grasp then you probably will want a Liberty Quest.','Tone'=>'Surreal','Tone_Text'=>'When an adventure has a strong dream-like quality, or even is a dream, where anything that occurs to the character will be, at least physically, undone when they awaken then you are in a Surreal Tone. It does not have to be a dream, many Daemons and Faeries choose to make reality seem like a dream in order to grant themselves extra abilities that are not so easily disbelieved.'),
		array('Attack'=>'Toxin', 'Attack_Text'=>'Toxin attacks are any attack where the body is poisoned rather than a direct physical assault being the major factor. Toxin wounds automatically stack with each other, so two Toxin Distracts become a Toxin Flesh, Three is a Toxin Maim etc. Toxin attacks can take several days to have their affect, others can kill instantly the difference depends upon the toxin, Chi Duration table can be used to determine the time, also Props and creatures may have handicaps such as “Slow poison” that reduce the speed.','Core'=>'Barber','Core_Text'=>'The character can swap wound Dæmons with another character for a cost of 1 Chi per wound if the new target of the wound is willing and 7 Chi per wound if unwilling','Handicap'=>'Stagnation', 'Handicap_Text'=>'Things get old, battered, rundown, ill, corrupt and slow. the longer something is left the more stagnant it becomes. This Handicap is for all those old things.','Incarna'=>'Poison/Potion','Incarna_Text'=>'Whether you wish to create some deadly Iocaine powder, or an invisibility serum, develop nerve gas, an anabolic steroid, mutagenic compound or play a character who has ingested so much toxin that their touch has become deadly, you want the Miasma Incarna.','Monster'=>'Mutant','Monster_Text'=>'The monster is a mutant or chimerical creature made from parts of others. This monster type is the oldest perhaps, you’ll find examples throughout the ancient world, particularly in Greek myth. The Mutant will often be larger, and may be malformed or unsymmetrical, with odd numbers of limbs, eyes, horns, or even heads. The Chimera will blend multiple animals together to create a new creature that combines features of all the “parent” creatures, preserving the best of all species. 1950s B-movie monsters are often of this type, giant ants, lizards, spiders, wasps, and even rabbits have been used. Classically of course, Cyclopses, Centaurs, Minotaurs, Satyrs, Gryphons (or Griffins), hippogriffs, dragons, sphinxes, manticores and of course the Chimera itself are all examples. You can also find examples in comicbook superheroes, especially those created by radioactive arachnids, or those with an X-gene.','Personality'=>'Vandal','Personality_Text'=>'<p>Gain Chi whenever you mock/insult/hurt someone, damage/mock something, or see the same.</p><p>Combat gain Chi when you play a Mortal or Carnage wound.</p>','Quest'=>'Sabotage / Poison / Corrupt','Quest_Text'=>'When the Ref needs you to poison a well, sabotage an experimental war-machine, or corrupt an innocent free-lance reporter, then you are on a Miasma Quest','Tone'=>'Horror','Tone_Text'=>'Preying on primal fears, the creeping dread of the unknown that lurks in the dark, monsters, killers, ghosts and things that go bump in the night the Horror Tone is all about unease, tension and scaring the characters (and maybe the players a little).'),
		array('Attack'=>'Gouge','Attack_Text'=>'Gouge attacks represent removing a scoop of the target, the standard gouge attack is a bite or an eye gouge. Gouge attacks can kill easily, but can also leave other Handicaps behind if the attacker wishes and the Ref agrees. Loss of sense would be appropriate for eye gouges for example. Gouge attacks do double damage at Mortal and Carnage level (x2) as things get eaten in a few short bites.','Core'=>'Master','Core_Text'=>'The character has one chosen environment in which they automatically gain one level of success.','Handicap'=>'Scarred', 'Handicap_Text'=>'Time heals all wounds it is said, but anyone who carries a prominant facial scar knows that while the pain may fade, the scars are always present. Scars don&#39;t have to be physical or visible to affect a character forever, they just need to worth a Handicap.','Incarna'=>'Flesh','Incarna_Text'=>'This is the most commonly selected Incarna, it is the Incarna of human beings and animals, nine times out of ten your character will have a Nature Formation Facet and the Flesh (Blood and Bone included) Incarna.','Monster'=>'Elemental','Monster_Text'=>'The Monster is a force of nature, perhaps a literal elemental or more likely metaphorical. Such Monsters always pull and play an additional Ordeal card, often as on collateral damage','Personality'=>'Shaman','Personality_Text'=>'<p>Gain Chi when you listen to another, offer someone help, or tell a story (lie?).</p><p>Combat gain Chi when you draw a &hearts;.</p>','Quest'=>'Nurture','Quest_Text'=>'When the Referee wants you to grow a plant, raise a child, look after something, maintain a piece of equipment then you are almost certainly involved in a Nature Quest','Tone'=>'Visceral / Sensual','Tone_Text'=>'When you want an adventure to have a deep emotional impact, or simply to have a sensual experience then the Tone should be set to Nature.'),
		array('Attack'=>'Lecture', 'Attack_Text'=>'A Lecture attack represents a stern talking to. It is a common way to install Duty, Madness and Paranoia Handicaps amongst others. Lecture attacks cause triple Distract (x3).','Core'=>'Philosopher','Core_Text'=>'Additional I-Ching (can be changing or unchanging and grant * power).','Handicap'=>'Paranoia','Handicap_Text'=>'Too much knowledge can be a bad thing. Knowing that a conspiracy exists can make you see its agents everywhere. No matter how crazy that may make you look to others. For a spy, Paranoia is a perfectly normal response to living amongst the enemy.','Incarna'=>'Data / Truth','Incarna_Text'=>'Perhaps you are trying to collect data, or want to write something down, or maybe you wish to play a living word, if so you are after the Orthodox Truth Formation Facet and Incarna.','Monster'=>'Tyrant','Monster_Text'=>'The Orthodox Monster is a tyrant, often a part of the system (in that it acts as a method of control over a population). A Tyrant monster may have troops that protect it, or work for it, or it may simply be so personally powerful that it can achieve its own goals.','Personality'=>'Mundane','Personality_Text'=>'<p>Gain Chi when you go with the majority, agree with another, or do as you are told.</p><p>Combat gain Chi when you prepare with a &diams; </p>','Quest'=>'Learn / Teach','Quest_Text'=>'Anytime an NPC dispatches you to learn as much as you can about something, or to tell everyone about a subject then you are probably involved in an Orthodox Quest.','Tone'=>'Historical / Documentary','Tone_Text'=>'When the story is trying for historical accuracy or documentary style reportage of events then the Tone may well be Orthodox.'),			
		array('Attack'=>'Fry','Attack_Text'=>'Fry attacks are the attack type used when things are hit by fire, or massive electrical bursts, plasma weapons are another good source of Fry attacks. Fry attacks can leave behind “Burns” rather than other scars, and can alter a targets Incarna to Phoenix whilst they are dying. Fry attacks do double damage to wood and flesh incarna (x2).','Core'=>'Doctor','Core_Text'=>'The character may choose one Incarna, when using or trying to effect that Incarna add one level of success.','Handicap'=>'Fatigued', 'Handicap_Text'=>'This handicap covers everything from laziness to sickness, some people and things just seem tired or useless most of the time.','Incarna'=>'Fire (Plasma)','Incarna_Text'=>'Whether you want to model a campfire, summon a blazing, conflagration elemental or play an alien composed of intelligent plasma filaments you will probably want a Phoenix Formation Facet.','Monster'=>'Paragon','Monster_Text'=>'The Monster is the embodiment of a positive force or emotion. Such Monsters are often a counter point, or are opposed to, another Monster. Phoenix Monsters are usually capable of causing positive (and sometimes negative) emotions via a Psychology Test in those that see them, and while they may be positive in nature, they are not necessarily good, or altruistic in their actions. The Phoenix itself is the embodiment of Resurrection, Hope and Faith, but is quite capable of burning destruction. The Golden Goose is another example, the embodiment of charity, but it evokes profound avarice in those who would own it. The unicorn is a symbol of purity, but is dangerous in the extreme to those it considers impure. Depictions of Angels are also perfect examples of positive embodiments.','Personality'=>'Healer','Personality_Text'=>'<p>Gain Chi when you give advice, heal a wound, or tell someone the truth (in your opinion). </p><p>Combat gain Chi when you play a &hearts; to heal.</p>','Quest'=>'Burn / Aid','Quest_Text'=>'If the adventure calls for you to set fires, perhaps burn a vampiric corpse or perhaps just to offer aid to another then the Quest is probably Phoenix','Tone'=>'Medical','Tone_Text'=>'When the bad guy is a virus, you&#39;re are trying to save the lives of hundreds of victims of a super-powered rampage downtown or if you are just playing a doctor (with or without a limp) then you may be involved in a Phoenix Tone'),
		array('Attack'=>'Erode', 'Attack_Text'=>'Erode attacks can take millions of years to affect a mountain or rock, but a sandstorm can have the same effect on a person or vehicle in a few minutes. Accelerated time, like a Never-Time, Paradox or Chronoclysm Bomb can also have Erode effects. Targets are usually “destroyed” rather than “killed” by Erode attacks. Erode attacks do double damage (x2) against Earth, Metal and Toil Incarna.','Core'=>'Greeter','Core_Text'=>'Gain Chi when they speak to a stranger or group of strangers.','Handicap'=>'Dependence', 'Handicap_Text'=>'We all have things that depend on us and things on which we depend. From family and society to addictions, or just having to plug a device in to get it too work. Children depend on their parents, and both can represent this with a Dependance Handicap.','Incarna'=>'Wood','Incarna_Text'=>'When you need to model plants, or any wooden structure, or if you have a pressing need to play a sentient vegetable then you&#39;ll want to look at a Quiet Formation Facet.','Monster'=>'Hush','Monster_Text'=>'The Quiet Monster is exactly that, almost (or entirely) silent. It is the creeping death of a hidden illness, or the cat-footed predator striking without warning that vanishes without trace. Quiet Monsters may pull an play an additional card when they act silently. Creatures like giant owls, snakes or cats, that stalk and hunt silently are good examples, as is a really creepy, floating mime. Many ghosts are also silent, and can fall into this type.','Personality'=>'Hermit','Personality_Text'=>'<p>Gain Chi when you act silently, selfishly or alone. </p><p>Combat gain Chi when you draw a &diams; </p>','Quest'=>'Study','Quest_Text'=>'If the Ref says you need to study up on something, perhaps those looming mid-terms, then you can be assured the Quest is Quiet','Tone'=>'Suspenseful','Tone_Text'=>'Suspense is the lifeblood of the Thriller. The Quiet Tone It governs and is governed by the unknown, creating a need to know and sense of anticipation in the players'),
		array('Attack'=>'Quash','Attack_Text'=>'Quash attacks are designed to destroy Descendants (especially weapon and armour props), rendering a victim open to other forms of attack.They have a tendency to destroy weapons, shields and armour props before affecting the characters own abilities. Quash attacks do double damage (x2) against Descendants (against Skill Descendants this is a +1 Wound Level automatically).','Core'=>'Evader','Core_Text'=>'The character is immune to one attack type or one level of Wound Dæmon (below the Rank of Carnage) E.g. all Fatal Wounds or all Hack wounds','Handicap'=>'Offensive','Handicap_Text'=>'Some people are just rude, others are actually bigoted, or prejudicied. Sometimes it can be how people behave, othertimes the offense can be physical, horrific burns and smells are also examples of the Handicap.','Incarna'=>'Defence','Incarna_Text'=>'If you are trying to build a suit of armour or even a castle, you will require the Rook Incarna. If you want to play a smart shield, possessed flak jacket, or haunted castle then you will want a Rook Formation Facet. The Defence Incarna automatically grants a Descendant the Passive Rook nimbed.','Monster'=>'Guardian','Monster_Text'=>'The Monster is a guardian, it guards a certain territory, path, treasure or person. It reduces all wounds caused to it by one level automatically. From Smaug to Fafnir dragons are often Guardians. Looking after a particular treasure or demanding tributes from a territory. The Vermis too are often associated with a particular territory while they sleep there.','Personality'=>'Guard','Personality_Text'=>'<p>Gain Chi when you act to protect another, are relied upon for any task, or ask a question. </p><p>Combat gain Chi when you play a &clubs; in defence.','Quest'=>'Secure / Guard','Quest_Text'=>'If an officer tells you to defend a door with your life, or if you have been tasked with securing the entrances and exits of an abandoned atmospheric processor colony building then you have gotten yourself into a Rook Quest.','Tone'=>'Restful','Tone_Text'=>'When the Tone is nice, peaceful and restful, when there is little or nothing going on in the plot right now, then you are probably enjoying the peacefulness of a Rook Tone.'),
		array('Attack'=>'Curse','Attack_Text'=>'Sin attacks range from Distracting offensive language to turning someone into a demonic lawn chair with Carnage level magic and may have a variety of final effects. It is not uncommon for the Curse attack to create Doomed Handicaps or, through Malformed Handicaps, turn the target into a frog - they can, of course, kill, blind and even change a Character&#39;s Personality or Core too). Curses do triple damage (x3) against Fate, Time and Illusion Incarna.','Core'=>'Consumer','Core_Text'=>'Gain Chi when you consume something (food, cigarette, drugs, money, credits, alcohol, human hearts, soul, etc -- pick one).','Handicap'=>'Persecuted', 'Handicap_Text'=>'Some people are abused or controlled by bullies, or society, others are persecuted by the gods themselves. Either way the Persecuted Handicap is how you model this.','Incarna'=>'Vice','Incarna_Text'=>'When you are building a descendant that is a vicious new street drug, or you want a black magic totem or you are playing an anthropomorphic representation of a deadly sin then you will want the Sin Formation Facet.','Monster'=>'Villain','Monster_Text'=>'The Sin Monster is an embodiment of a specific vice, taboo, or sin, often in the form of a human Villain. They often have annexes and Handicaps that reflect their embodied vice or sin, and are often at least partially supernatural. Sin Monsters may double their Score when appropriate to their embodiment. The genocidal maniac, of the sort British Intelligence seems to tangle with repeatedly, could be a Sin Monster. The ever-hungry cannibal spirit, the Wendigo is definitely an example, as is the Sexual-predatory Lust-embodied Vampire.','Personality'=>'Fiend','Personality_Text'=>'<p>Gain Chi when you succumb to temptation, play devil’s advocate, disagree, use sarcasm, or break (or bend) a rule. </p><p>Combat gain Chi when you play a Maiming or Crippling wound.</p>','Quest'=>'Seduce / Abuse','Quest_Text'=>'Sin Quests are tales of dark deeds, sexual conquest and abuse. They are not for the faint hearted.','Tone'=>'Immoral','Tone_Text'=>'When the characters are up to no good, it always helps if you&#39;ve got a Tone to match and the Sin Tone will match almost any dark deed.'),
		array('Attack'=>'Hack','Attack_Text'=>'Hacks are an attempt to cut sections of the target off or, in the case of Computer systems, Hack wounds can allow the hacker to control the system. Assuming the wounds created produced a “Hacked” Handicap. Hack scars can include malformed Handicaps for the loss of limbs etc that can occur. Hacks do double damage (x2) against Wood (Quiet), Flesh (Nature), Orthodox (Data), and Toil (Craft) Incarna.','Core'=>'Attacker','Core_Text'=>'Character has a “special move” that when used adds two success levels to the result automatically. In Combat this means the Special move can draw and play an extra two cards, or add one or two levels to one or two cards','Handicap'=>'Defensive', 'Handicap_Text'=>'Some people are quick to strike back when they feel threatened. It can become a big issue for them, bordering on Paranoia, where they feel they must respond to criticism, or become hypervigilant, or even hyperapologetic.','Incarna'=>'Metal','Incarna_Text'=>'Whether you&#39;re thinking about swords, cars, planes, or full-body cyborgs, a Trial Formation Facet will grant you that Metal Incarna.','Monster'=>'Killer','Monster_Text'=>'The Monster is a deadly combat specialist of some sort. All wounds it causes are one level greater than drawn. Carnage draw a second card when played and add that without increase.','Personality'=>'Gladiator','Personality_Text'=>'<p>Gain Chi when you compete against another, argue, or fight.</p><p>Combat gain Chi when a &spades; is played on you.</p>','Quest'=>'Compete','Quest_Text'=>'If you must best all the members of Cobra-kai in a Karate competition, if you are representing your colony in the interstellar olympics, or if you must win the latest hoverboard in a streetrace, you are embroiled in a Trial Quest.','Tone'=>'Combatative','Tone_Text'=>'Whether you are talking entrenched battlefield manoeuvres or simply a screaming exchange of malign curse words, you may benefit from a Trial Tone.'),
		array('Attack'=>'Convert', 'Attack_Text'=>'Conversion wounds often create new Handicaps in the targets, these can be religious Duty Handicaps or similar, or alter Core, Personality or Incarna. Convert attacks do triple damage (x3) when they create Carnage wounds.','Core'=>'Preacher','Core_Text'=>'Gain Chi whenever you talk about your beliefs, quote a text, or act in accord with your beliefs.','Handicap'=>'Apathy', 'Handicap_Text'=>'The modern disease, apathy can simply be not wanting to do something, it can be a symptom of a serious problem like dpression, or just be a projection on those who are unable to do, by those who can.','Incarna'=>'Energy','Incarna_Text'=>'Maybe you want to model a power source or you&#39;d like to train electricity or you just want to play an alien that is a living psionic energy field, well then the Virtue Incarna is for you.','Monster'=>'Friend','Monster_Text'=>'The Monster is a ‘Friendly’ monster, that will almost certainly be misunderstood and attacked by some. These monsters gain a success level (or draw and play an additional card) when working with another. A cynical, but big-hearted ogre; a being created from stitched together corpses; a dark-elf ranger with a unicorn necklace; or perhaps even an Electric Mouse.','Personality'=>'Saint','Personality_Text'=>'<p>Gain Chi when you show Compassion, help another or resist temptation. </p><p>Combat gain Chi when you are attacked with a &diams; </p>','Quest'=>'Convert / Protect','Quest_Text'=>'When you are tasked with a literal mission to convert a bunch on the ungodly then you are probably under the influence of a Virtue Quest.','Tone'=>'Romantic','Tone_Text'=>'Momentum and not love may make the world go around, but love can certainly drive a narrative on, and the Virtue Tone is the main way it does it. Traditionally, romance is a hero and a heroine uniting against the odds, but in these post-modern days that simple equation has a whole lot of other variants.'),
		array('Attack'=>'Snare','Attack_Text'=>'Wyrd attacks can be used to capture (and Confine) as well as kill. Additionally snares can be set, and left to attack later on their own. A prepared snare wound can sit waiting as a trap, until someone blunders into it (in fact all traps are essentially snare attacks [although the actual wound type does vary from attack to attack]). Disabling a Snare requires defeating it twice (initially dodging, parrying or ignoring it with a Club &clubs; and then disabling it with a Diamond &diams; of equal or higher Pips) otherwise it may affect anyone else that moves through the area/Stage. Snares usually take a while to set (you can&#39;t dig a pit trap as easily as swinging a shovel at someone) unless using Magic. Refs decide.','Core'=>'Cheater','Core_Text'=>'Chi/Sway cost or difficulty for one chosen effect is halved. (E.g. Reload for 4 Chi, specific sidestep for half price, increase Scale for 1/4 Max Chi, etc.)','Handicap'=>'Doomed','Handicap_Text'=>'Cursed, star-crossed, destinied, fated, or just inevitably dying. This is a flexible Handicap that can cover a lot of scenarios when the gods just seem to have it in for you.','Incarna'=>'Fate / Sway','Incarna_Text'=>'Magick, Curses and the magical creatures of the Wyrd including some Fairies (or Fæ if you prefer), and some Eelafin and Solos may have a Wyrd Incarna as do the beings responsible for reality itself.','Monster'=>'Doomweaver','Monster_Text'=>'The monster is a creature of the Fæ, it can draw and play Yarn cards or Wyrd Tarot cards. The Wyrd Monster usually has a Wyrd hand with extra cards equal to its Scale Reduced (minimum of +1). A powerful Wyrd Monster might have up to 14 cards. Any fairy creatures like Unicorns, Leprechauns, Trolls, Cait-sith, up to a 14 card Sidhe Duke are good examples.','Personality'=>'Judge','Personality_Text'=>'<p>Gain Chi when you ask questions, act impartially or are asked for your opinion or verdict. </p><p>  Combat gain Chi when you prepare with a &clubs;','Quest'=>'Capture / Judge','Quest_Text'=>'If you are asked to sit in judgement on a decision, or if you must bring in a no good gang of horse rustlers, or just capture hill 14 before dawn, then you may be ensnared in a Wyrd Quest.','Tone'=>'Magical','Tone_Text'=>'When dark wizards gather to perform dark deeds, or elves sing, then you may be ensorcelled by a Wyrd Tone.'),
		array('Attack'=>'Yank','Attack_Text'=>'Yonder attacks can capture and bind (creating Confined Hanicaps), and pull and drag their victims. Yank attacks can unbalance the target, pulling them off balance, etc. Yank attacks do triple damage (x3) to moving targets.','Core'=>'Traveller','Core_Text'=>'The Character has an additional Annex (1-11 Skill, 12-21 Talent, 22-26 Power) that grants an extra mode of Travel. E.g. Fleet-footed Skill, Flying Talent or a Lea Walking Power.','Handicap'=>'Loss-Of-Sense','Handicap_Text'=>'When a Character is blinded or deafened they are obviously Handicapped, but what about those who suffer from a lack of balance, or don&#39;t know when they are hungry, or simply have no common sense. This Handicap will cover them.','Incarna'=>'Space (Location)','Incarna_Text'=>'When you need to build a Location, or play a sentient building (or grove), then you will want a Yonder Formation Facet.','Monster'=>'Alien','Monster_Text'=>'The Monster is an alien, an outsider. It may just be a metaphor for alienation, or literally be an extra-(or ultra)-terrestrial. Such monsters are usually obvious and inhuman, not just to look at, but in the way they think and behave. They have apparently supernatural powers and abilities, but often make do with advanced technologies (in the form of additional Descendants). From little grey Eusaiveans, through to pod people and pepper-pot shaped engines of hate, all the way to face-hugging xenomorphic space-wasps, there are plenty of aliens.','Personality'=>'Scout','Personality_Text'=>'<p>Gain Chi when you gain information, see a new place, answer a question, or tell someone what you have experienced. </p><p>Combat gain Chi when you act at Range (paying Range costs or using Range Nimbeds).</p>','Quest'=>'Follow / Travel','Quest_Text'=>'If you&#39;ve ever shouted &quot;Quick follow that car&quot; or followed a Treasure map, or had to reach a destination for any reason, then you have been involved in a Yonder Quest.','Tone'=>'Odyssey / Road movie','Tone_Text'=>'When the song of the open road, sea, sky or space-lanes calls to you it calls in a Yonder Tone.'),
		array('Attack'=>'Kick','Attack_Text'=>'Kick attacks are exactly what they say on tin. A kick, whether it be from an extended leg, or the type of powerful knock that you get when you misfire a shotgun, moves you or the target. A Kick draws a second card immediately that signifies the damage taken by being knocked down.','Core'=>'Meddler','Core_Text'=>'Character can store and usually has an additional point of Twist (whether they can gain Twists or not). Normally the character would be restricted to the number of Handicaps that they had and require a Dæmonic Handicap or Annex to generate Twists. The extra Twist will naturally regenerate once a Scene.','Handicap'=>'Doubt','Handicap_Text'=>'Doubt is the opposite of belief and yet walks hand in hand with it. Mistrust and Suspicion are related, and these Handicaps affect a lot of people. Think about whether you trust your politicians, police or your friends.','Incarna'=>'Faith','Incarna_Text'=>'It is said that it is harder to kill an idea than a man, even more so a belief. Whether a prayer, a belief, or even a god that you are trying to model, you should consider a Zeal Incarna.','Monster'=>'Radical','Monster_Text'=>'The Monster is an extremist, usually religious or political in nature. When acting according to their nature, or following their belief system, they may draw and play an additional Ordeal card, increase a Wound as they cause it, or reduce a Wound they receive. However, if they act outside of their nature, they are restricted by an automatic GRT of 1. The monster could be an evil priest, a terrorist, a devil, a djinn, or perhaps even the Angel of Death.','Personality'=>'Fanatic','Personality_Text'=>'<p>Gain Chi when you act about or talk about what you are fanatical about.</p><p>Combat gain Chi when you play a &diams; as an action rather than attack or preparation.</p>','Quest'=>'Flee','Quest_Text'=>'Any time you start running and just keep going you are under the thrall of a Zeal Quest','Tone'=>'Chase','Tone_Text'=>'Any chase, whether in a car, ship, plane or on foot across rooftops or through streets is an example of a Chase Tone.') ) );
	//------------------------Annex-Facet-Core------------------------------------
	$retvar = array('message'=>'Character Facet Core Loaded', 'package'=>(int)$package++);
	break;
	case 6:
	$col=array();
	$col[]=array('Name'=>'Annex_Channel', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'annex-channel', 'Tooltip'=>'What an Annex is like that Channels through this Facet?');
	$col[]=array('Name'=>'Annex_Root', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'annex-root', 'Tooltip'=>'What is an Annex like that is rooted in this Facet?');
	$col[]=array('Name'=>'Nimbed_Expand', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'nimbed-expand', 'Tooltip'=>'How does this Facet Expand the Annex?');
	$col[]=array('Name'=>'Nimbed_Focus', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'nimbed-focus', 'Tooltip'=>'How does this Facet Focus the Annex?');
	$col[]=array('Name'=>'Nimbed_Reward', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'nimbed-reward', 'Tooltip'=>'How does this Facet Reward the User of the Annex?');
	$col[]=array('Name'=>'Nimbed_Trick', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'nimbed-trick', 'Tooltip'=>'What Trick does this Facet grant an Annex?');
	$col[]=array('Name'=>'Umbral_Limit', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'umbral-limit', 'Tooltip'=>'How does this Facet Limit the Annex?');
	$col[]=array('Name'=>'Umbral_Need', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'umbral-need', 'Tooltip'=>'What does this Facet Need to power the Annex?');
	$col[]=array('Name'=>'Umbral_Sacrifice', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'umbral-sacrifice', 'Tooltip'=>'What Sacrifice does the Facet demand to use the Annex?');
	$col[]=array('Name'=>'Umbral_Special', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'umbral-special', 'Tooltip'=>'What Special cost or requirement does ht Facet add to the Annex?');
	$this->AddTable($package,"Annex_Facets",$col, '', array(array('LocalCol'=>'Annex_Facets_Id', 'Table'=>'Facets','ForCol'=>'Facets_Id')), array('Description'=>'This extends the Facets, adding all manner of Annex notes','Tooltip'=>'A Facet&#39;s Annex components', 'HelpText'=>'All Annexes are made by blending Facet Proficiencies together.', 'Code'=>'Extend', 'ContainerPost'=>FALSE, 'DisplayRow'=>'<details data-level="%level%" data-help="%tab-help%" data-tooltip="%tab-tooltip%" ><summary>Annex Facet Features</summary><details class="facet-details"><summary class="facet-channel"><strong>Channel: </strong></summary><p class="annex-channel">%Annex_Channel%</p></details><details class="facet-details"><summary facet-root"><strong>Root</strong></summary><p class="annex-root">%Annex_Root%</p></details><details class="facet-details"><summary class="facet-nimbeds">Nimbeds</sumary><details class="facet=expand"><summary><strong>Expand</strong></summary><p class="nimbed-expand">%Nimbed_Expand%</p></details><details class="facet-focus"><summary>Focus</summary><p class="nimbed-focus">%Nimbed_Focus%</p></details><details class="facet-reward"><summary><strong>Reward</strong></summary><p class="nimbed-reward">%Nimbed_Reward%</p></details><details class="facet-trick"><summary><strong>Trick</strong></summary><p class="nimbed-trick">%Nimbed_Trick%</p></details></details><details class="facet-details"><summary><strong>Umbrals</strong></summary><details class="facet-limit"><summary><strong>Limit</strong></summary><p class="umbral-limit">%Umbral_Limit%</p></details><details class="facet-need"><summary><strong>Need</strong></summary><p class="umbral-need">%Umbral_Need%</p></details><details><summary>Sacrifice</summary><p class="umbral-sacrifice">%Umbral_Sacrifice%</p></details><details class="facet-special"><summary><strong>Special</strong></summary><p class="umbral-special">%Umbral_Special%</p></details></details></details>','Template'=>''), array(
	array('Annex_Channel'=>'Emotional / Spiritual','Annex_Root'=>'Art / Artistic','Nimbed_Expand'=>'Art, add One Card Psychological Test (Fear).','Nimbed_Focus'=>'Annex affects Target&#39;s Personality Annex by preference','Nimbed_Reward'=>'Spiritual (Gain Awe Nimbed Boon Reduced Chi).','Nimbed_Trick'=>'Artistry, when playing any Ace immediately Draw and Play an additional card.','Umbral_Limit'=>'Emotional effects only or Halve Score.','Umbral_Need'=>'Must be in a specific Emotional state to activate (e.g. Happy).','Umbral_Sacrifice'=>'Spiritual (Awe Umbral Boon Reduced Yang).','Umbral_Special'=>'Audience (must have an Audience of at least Annex Boon Double Reduced as Yarn: e.g Boon 50 = 15-51 people)'),
	array('Annex_Channel'=>'Mass / Weight/ Ownership','Annex_Root'=>'Object, Ownership and Wealth','Nimbed_Expand'=> 'Durable, add Burden Nimbed Boon Reduced to Difficulty to dispel effects.','Nimbed_Focus'=>'Annex affects Target&#39;s Physical Descendants by preference','Nimbed_Reward'=>'Wealth (Gain Burden Nimbed Boon Reduced Chi)','Nimbed_Trick'=>'Echoes, one card played during Annex action may be recovered played again during GRT','Umbral_Limit'=>'Physical effects only or Halve Score.','Umbral_Need'=>'Prop, must have a specific Physical Descendant (of cost at least equal to Annex Boon Reduced) that is not in GRT to activate.','Umbral_Sacrifice'=>'Wealth (Annex Boon Double Reduced Chi)','Umbral_Special'=>'Slow, add Burden Umbral Boon Reduced to Annex&#39;s RT.'),
	array( 'Annex_Channel'=>'Delicate / Precise / Complex','Annex_Root'=>'Construction / Manufacture / Maintenance','Nimbed_Expand'=>'Add a Success Level Craft Boon Reduced times a day.','Nimbed_Focus'=>' The Annex is highly adaptable, programmable, changeable or controllable. Add a Success Level to any well described use at Ref’s discretion.','Nimbed_Reward'=>'Preparation, Draw and play a card in preparation.','Nimbed_Trick'=>'Delicate, add Craft Nimbed Boon Reduced to any Diamond played in Preparation or Creation.','Umbral_Limit'=>'May only affect Skills (including Descendants and Extras) or Halve Score.','Umbral_Need'=>'Proficiencies, must have Annex Boon Double Reduced appropriate Proficiencies (preferred for a Descendant).','Umbral_Sacrifice'=>'Preparation, Ordeal cards with Pips equal to Annex Boon Reduced must be spent on Preparing the Annex - which are then discarded.','Umbral_Special'=>'Delicate, Wounds that target the Annex gain a Level.'),
	array('Annex_Channel'=>'Control / Psychology','Annex_Root'=>'Politics / Social','Nimbed_Expand'=>'Add a Success Level when affecting multiple Targets.','Nimbed_Focus'=>'Mastery, add a Success Level when used with an additional appropriate Proficiency.','Nimbed_Reward'=>'Political / Social (Gain Dominion Nimbed Boon Reduced Chi).','Nimbed_Trick'=>'Area of effect, the Annex may affect an Area (see Sway Table) equal in size to the Dominion Nimbed Boon Reduced as Yarn.','Umbral_Limit'=>' Maximum number of targets (Annex Boon Double Reduced as Yarn) if affecting more Targets Halve Score','Umbral_Need'=>'Pact, must have a specific Pact Descendant of cost at least equal to Annex Boon.','Umbral_Sacrifice'=>'Political / Social (Dominion Umbral Boon Reduced Yang).','Umbral_Special'=>'May only be used as directed or requested by another'),
	array('Annex_Channel'=>'Hide / Confuse','Annex_Root'=>'Secretive, occult or Mysterious','Nimbed_Expand'=>'Add a Success Level to any Failures with this Annex.','Nimbed_Focus'=>'Add a Success Level when the User is unobserved or hidden.','Nimbed_Reward'=>'Occult, the effect of this Annex is hidden, undetectable or untraceable (Difficulty to spot Enigma Nimbed Boon). In combat an attack (or defence) with this Nimbed requires extra Pips (equal to the Enigma Nimbed Boon Reduced) to defend (or penetrate).','Nimbed_Trick'=>'Secretive, may play Preparation cards face down.','Umbral_Limit'=>'When acting directly on a Target Halve Score.','Umbral_Need'=>'Secrecy, the Annex must be used in secret.','Umbral_Sacrifice'=>'Occult (Enigma Umbral Boon Reduced Yin).','Umbral_Special'=>'Questions, must ask Umbral Boon Reduced questions to activate.'),
	array('Annex_Channel'=>'Aggression / Noise / Action','Annex_Root'=>'Water / Negative emotions (Anger)','Nimbed_Expand'=>'Intimidation, add One Card Psychological Test (Fear)','Nimbed_Focus'=>'Annex may set the Tone to the match Annex Annex_Root or Annex_Channel.','Nimbed_Reward'=>'Blood, Sweat &amp; Tears, any Wound caused by the Annex is automatically aggravated One Level.','Nimbed_Trick'=>'Furious, Annex may Play an additional card on the Annex&#39;s action. ','Umbral_Limit'=>'Must make noise or Halve Score.','Umbral_Need'=>'Must be in a specific emotional state to activate (e.g. Angry).','Umbral_Sacrifice'=>'Blood, Sweat &amp; Tears (Annex Boon Double Reduced Success Levels Sacrificed on Failure).','Umbral_Special'=>'All cards must be played on a single effect and target.'),
	array('Annex_Channel'=>'Strength / Sound / Textile','Annex_Root'=>'Breath / Hands','Nimbed_Expand'=>'Strong, add Gossamer Nimbed Boon Reduced to Annex Boon.','Nimbed_Focus'=>'Can use scenery, atmosphere, and weather to add a Success Level at Referee&#39;s discretion','Nimbed_Reward'=>'Words, the Annex will allow a message of Gossamer Nimbed Boon Reduced Words to be transferred to the Target and for the Target to respond the same, during the Annex&#39;s action.','Nimbed_Trick'=>'Bounces, may Draw and Play an additional card to pay for extra Targets (+3 Pips per Target). Defences with this Nimbed can bounce Gossamer Nimbed Boon Double Reduced cards back on the attacker once per Scene.','Umbral_Limit'=>'Physical contact with Target must be made or Halve Score.','Umbral_Need'=>'Must be used in a loud or windy environment.','Umbral_Sacrifice'=>'Words, must speak Annex Boon Reduced syllables to activate.','Umbral_Special'=>'Fumble, the Annex can go wrong if you roll minimum on the Gossamer Boon die. The Referee may control the Annex&#39;s action and make it attack the User or an Ally.'),
	array('Annex_Channel'=>'Lies / Deception / Fiction','Annex_Root'=>'Fiction / Banned / Heretical','Nimbed_Expand'=>'Indirect, the Annex can work through another Character or Descendant. (E.g. Eelafin Senses can have this Nimbed allowing the Eelafin to perceive through the senses of nearby animals).','Nimbed_Focus'=>'Mislead, the Annex looks and acts like another type of Annex and can even leave Red Herring (Heresy Boon based) clues.','Nimbed_Reward'=>'Accuracy, add Heresy Nimbed Boon Reduced as accidently discovered truths or Pips of Penetration or Range.','Nimbed_Trick'=>'Feint, any time the Annex plays a Distract it may automatically Draw and Play another card.','Umbral_Limit'=>'Cannot be used in Specific Circumstance or Environment or Halve Score.','Umbral_Need'=>'Communication, a message must be passed or spoken to the target.','Umbral_Sacrifice'=>' Accuracy, never completely accurate. Will activate, but Opponent/Ref may Draw and Play Annex Boon Double Reduced Ordeal Cards to represent inaccuracy)','Umbral_Special'=>'Fabrication, all effects can be undone, or destroyed, more easily (Umbral Boon Reduced from difficulty to dispel)' ),
	array('Annex_Channel'=>'Motion / Endurance','Annex_Root'=>'Momentum / Mass / Survival','Nimbed_Expand'=>'Causes motion in the Target (Inertia Nimbed Boon metres for small objects and Inertia Nimbed Boon Reduced for other Characters and larger objects).','Nimbed_Focus'=>'Relative Motion, if the User and Target are moving relative to each other add a Success Level.','Nimbed_Reward'=>'Time, the target of the Annex (or the Defence that stops the Annex) is affected by an immediate GRT equal to the Inertia Nimbed Boon Double Reduced.','Nimbed_Trick'=>'Momentum, any Spade with a face value lower or equal to Inertia Nimbed Boon Reduced x2 may add directly to the Pips of the card it is attacking with. E.g. Play a Five of Spades (Flesh) as preparation and then a Jack of diamonds (Crippling) to create a Carnage wound (and a random second card).','Umbral_Limit'=>'Score Halved if User is moving.','Umbral_Need'=>'Relative Motion, Target and/or User must be moving.','Umbral_Sacrifice'=>'Time, the User must wait (taking a Half-Action only) Annex Boon Double Reduced RT phases (or Pips are discarded on RT) before Activation.','Umbral_Special'=>' Charging Time, the User of the Annex must charge as though in GRT equal to the Inertia Umbral Boon Double Reduced (1) before use. Charging Time reduces GRT after Activation.'),
	array('Annex_Channel'=>'Illusions / Deceptions / Satire / Mimicry','Annex_Root'=>'Jokes / Humour','Nimbed_Expand'=>'The Annex has its effect regardless of any intervening obstacles or defences (unless those obstacles or defences have Annexes containing this Nimbed also). In combat, if the attack is successfully defended against (without this Nimbed) or fails because of Range then the Target immediately draws Jeer Nimbed Boon Double Reduced cards as unsoakable wounds.','Nimbed_Focus'=>'Humour, add Jeer Boon die to the Score/Pips if the action is humorous, funny or mimics another.','Nimbed_Reward'=>'Dignity (Gain Jeer Nimbed Boon Reduced Chi).','Nimbed_Trick'=>'Hearts Flush, anytime the Annex plays more than one Heart all Hearts are one Level higher.','Umbral_Limit'=>'Must make use of the Location and scenery or Halve Score.','Umbral_Need'=>'Humour, someone must be laughing to Activate.','Umbral_Sacrifice'=>'Dignity, (Jeer Umbral Boon Reduced Yin).','Umbral_Special'=>'Limited Duration (Jeer Umbral Boon as Yarn) after which effects may fade. (E.g. After a few minutes Wounds caused by the Annex will disappear)'),
	array('Annex_Channel'=>'Senses / Perception / Lockpicking / Penetration','Annex_Root'=>'Logical / Intelligence / Investigation','Nimbed_Expand'=>'Penetrating, against targets with defences the Annex gains a Penetration bonus. All attacking Ordeal cards add Key Nimbed Boon Reduced Pips of Penetration.','Nimbed_Focus'=>'Information, the Annex will reveal Key Nimbed Boon Reduced pieces of information about the target that may be pertinent E.g. Handicaps, Umbrals, Personality, Geometry, I-Ching, etc.','Nimbed_Reward'=>'Thoughts, (Gain Key Nimbed Boon Reduced Chi)','Nimbed_Trick'=>'Straight, when playing cards any cards that form a sequence(e.g. Q&clubs;,K&diams;,A&spades;) all count as the Highest Wound Level in the straight (or One Level Higher if they are all the same).','Umbral_Limit'=>'Mental effects only or Halve Score.','Umbral_Need'=>'Information, User must have information about the target before Activation ','Umbral_Sacrifice'=>'Thoughts, (Annex Boon Double Reduced Chi)','Umbral_Special'=>'Must have a witnessable effect or leave traceable evidence.'),
	array('Annex_Channel'=>'Luck / Magic / Games','Annex_Root'=>'Dream / Game / Luck / Freedom','Nimbed_Expand'=>'Ignore Liberty Boon Double Reduced Umbrals in this Annex.','Nimbed_Focus'=>'Unique use, the Annex can be used by others (up to Liberty Nimbed Boon Reduced) at the same time,  the Annexes Umbrals effect each user individually.','Nimbed_Reward'=>'Destiny, Draw Liberty Nimbed Boon Double Reduced cards and add them to your Wyrd Tarot Hand or Ordeal Pool.','Nimbed_Trick'=>'Annex uses only half an Annex slot. Two Powers both with this Nimbed would fill one Power slot. This also reduces GRT for this Annex by 1.','Umbral_Limit'=>'Creative effects only or Halve Score.','Umbral_Need'=>' Unique use, cannot be used for the same effect twice.','Umbral_Sacrifice'=>'Destiny, discard a Wyrd Tarot or Yarn Card with Pips at least equal to the Annex Boon Double Reduced.','Umbral_Special'=>'Easily Lost. Wounds automatically target the Annex when applying damage and add Liberty Umbral Boon Reduced to Pips of the Wound card.'),
	array('Annex_Channel'=>'Chemical / Toxin','Annex_Root'=>'Chemical / Rotting / Foulness / Corruption','Nimbed_Expand'=>' Sickening, add One Card Psychological Test (Revulsion).','Nimbed_Focus'=>'Communicable: Spreads by contact Miasma Nimbed Boon Reduced times. In combat a Character with this Nimbed may draw and play an Ordeal card whenever a Character wounded by this Annex touches another up to Miasma Nimbed Boon Reduced times.','Nimbed_Reward'=>'Youth, de-ages User Miasma Nimbed Boon Reduced as Yarn Extend Duration each use. ','Nimbed_Trick'=>'Corruption, Wounds caused by the Annex will automatically aggravate up one level each Phase of GRT to a maximum of Miasma Nimbed Boon Double Reduced (1-3 levels).','Umbral_Limit'=>'May be used to negative effects only or Halve Score.','Umbral_Need'=>'Handicap, must have a specific Handicap of Boon equal to Annex Boon reduced.','Umbral_Sacrifice'=>'Youth, ages User Annex Boon Double Reduced as Yarn  Extend Duration each use. ','Umbral_Special'=>'Corruption, the products and effects of the Annex look, smell and taste bad.'),
	array('Annex_Channel'=>'Nature / Nurturing','Annex_Root'=>'Natural Abilities','Nimbed_Expand'=>'The Annex doubles its score when affecting Nature Boon Double Reduced Incarna, select the Incarna during Annex creation. In Combat if affecting a correct Incarna all Ordeal cards are added again (x2 damage becomes x3)','Nimbed_Focus'=>'Life, the Annex&#39;s effects are motile and responsive and will actively resist attempts to “dispel” it. Add Nature Reduced Boon to difficulty to dispel or Heal as inanimate objects dodge and wounds bite back.','Nimbed_Reward'=>'Blood Sacrifice, any time the Annex Draws a Distract you may immediately Discard and Draw again.','Nimbed_Trick'=>'Natural Ability, the Annex grants the user resistance to similar Powers based on the Nature Nimbed Boon Reduced. E.g. A Venom Annex with Nature Nimbed Boon 17 would grant a +5 to any roll or Ordeal card to resist poisons, Venoms etc.','Umbral_Limit'=>'Halve Score when affecting Nature Umbral Boon Reduced Incarna','Umbral_Need'=>' Life, can only affect living beings and materials.','Umbral_Sacrifice'=>'Blood Sacrifice, automatically apply Annex Boon Double Reduced Flesh Wounds to the User .','Umbral_Special'=>'Natural Ability. The Annex is always on and can never be turned off. In situations where the Annex would not be advantageous it will work against the User (e.g. Animal Senses could hurt the User if a Flashbang grenade goes off).'),
	array('Annex_Channel'=>'Teaching / Learning','Annex_Root'=>'Lore / Knowledge','Nimbed_Expand'=>'Grants Orthodox Boon in Yin if successful or in Yang if it fails.','Nimbed_Focus'=>'Facts, the Annex grants the user Orthodox Boon Reduced facts about the Target if successful.','Nimbed_Reward'=>'Additional Annex Slot, the Annex automatically grants Orthodox Nimbed Boon Reduced Extra Proficiencies or add Orthodox Nimbed Boon Double Reduced Skill Annexes pertaining to the Master Annex. E.g. A Magic Lore Annex with Orthodox Boon 13 grants 4 extra Proficiency Slots, or 1 Skill slot.','Nimbed_Trick'=>'Diamonds Flush, anytime the Annex plays more than one Diamond, all Diamonds are one Level higher.','Umbral_Limit'=>'Will only work in a specific environment in all others Halve Score.','Umbral_Need'=>'Specific Trigger, can only activate under specific circumstances.','Umbral_Sacrifice'=>'Additional Annex Slot, The Annex fills an additional, smaller slot (e.g. Talent uses a Skill and Talent slot, a Skill would use an extra Proficiency slot.)','Umbral_Special'=>'The effects of the Annex may be completely undone by a specific circumstance. E.g. The effects of a Vampiric power may be undone by killing the Vampire, or a magicians spells may be broken by spilling their blood.'),
	array('Annex_Channel'=>'Healing / Burning','Annex_Root'=>'Passion / Fire / Healing','Nimbed_Expand'=>'The Annex may cause Phoenix Nimbed Boon Double Reduced Umbrals to affect the Annex Target in addition to the user. The Target must pay those Umbrals or exist in a state of GRT for the Phoenix Boon Reduced.','Nimbed_Focus'=>'Add the Phoenix Nimbed Boon die to the Annex Score. This can also be used to enhance the Pips of one card being played.','Nimbed_Reward'=>'Fuel, Food or Ammunition (Gain Phoenix Nimbed Boon Reduced Chi)','Nimbed_Trick'=>'All Hearts suit Ordeal Cards add Phoenix Boon Reduced Pips automatically when played in this Annex’s action.','Umbral_Limit'=>' Uncontrolled, Referee controls Annex or Halve Score.','Umbral_Need'=>'Specific Incarna, can only Target Phoenix Umbral Boon Reduced Incarnas.','Umbral_Sacrifice'=>'Fuel, Food or Ammunition (Annex Boon Double Reduced Chi)','Umbral_Special'=>'Recharge, roll over the Phoenix Umbral Boon Reduced on 1d9 to recharge the Annex after use. These recharge attempts have an RT equal to the Annex&#39;s normal GRT and a GRT of 0.'),
	array('Annex_Channel'=>'Silent / Wooden / Book learning','Annex_Root'=>'Books / Mental / Serene / Meditation','Nimbed_Expand'=>'The Annex automatically activates in response to certain stimuli. When activated by the “trigger” the use does not use up a character’s action. This Nimbed is required to allow an Annex or Descendant to be added to an Ordeal Proficiency / Initiative roll. RT applies but not GRT (see also Rook “Passive” Nimbed).','Nimbed_Focus'=>'Subtle, The Annex&#39;s use can be so subtle that it may require days of study to determine the complete effects of the Annex. Whilst there will be an immediate obvious effect, there will be other more subtle effects at play. Add Quiet Boon Reduced to the Pips of all Ordeal cards &#39;prepared&#39; with this Annex.','Nimbed_Reward'=>'Practice, Draw Quiet Nimbed Boon Double Reduced Extra cards in the Annex&#39;s action.','Nimbed_Trick'=>' Sets, the Annex may play multiple cards of the same Pips as though they were a single card. E.g. Playing 5&spades;, 5&clubs;, 5&diams;, 9&spades; and 9&hearts; counts as playing only Two cards.','Umbral_Limit'=>' Must be used silently or Halve Score.','Umbral_Need'=>'Tranquility, the User cannot be affected by strong emotions.','Umbral_Sacrifice'=>'Practice, the User must practice the Annex for Annex Boon Reduced hours each week for Quiet Umbral Boon Reduced Weeks before they can activate. Failure to Practice will stop Annex from Activating.','Umbral_Special'=>'Must roll over the Quiet Umbral Boon Value on a d200, Yin may be spent on d6s to increase the roll to activate the Annex.'),
	array('Annex_Channel'=>'Defense / Protection','Annex_Root'=>'Passive / Defensive / Strategy ','Nimbed_Expand'=>'Passive. The Annex is rests between uses in a passive mode (using the last active roll&#39;s score). Senses and Defences often have this Nimbed. In combat a Defence such as Armour with this Nimbed is always able to play Rook Nimbed Boon Reduced Ordeal cards in defence from your pool.','Nimbed_Focus'=>'The effects of the Annex defend themselves rather than be dispelled. Wounds add Rook Nimbed Boon Reduced to their Pips for Healing, Descendants receive a &quot;Defence&quot; Skill with a Boon equal to the Rook Nimbed Boon. ','Nimbed_Reward'=>'Success, add One Success Level to any action or card Rook Nimbed Boon Reduced times per day.','Nimbed_Trick'=>'Club Flush, any time the Annex plays more than one Club all Clubs are One Level Higher.','Umbral_Limit'=>'Halve Score if used offensively.','Umbral_Need'=>'Danger, will only activate if the Ordeal Stakes are High.','Umbral_Sacrifice'=>'Success, cumulative -Rook Umbral Boon Reduced from the Score each time the Annex is used in a Scene.','Umbral_Special'=>' Saving Throw, Target and User both roll Rook, if the Target rolls higher they receive a Proficiency in &quot;Resist (this Annex)&quot; (assuming they have a free Proficiency Slot) and the Score is Halved for this action.'),
	array('Annex_Channel'=>'Vice / Sin / Evil','Annex_Root'=>'Evil / Unethical / Immoral','Nimbed_Expand'=>'The target of the Annex is drained of Sin Boon points of Chi which the user receives.','Nimbed_Focus'=>'Pain, Add a Success level when the Annex can affect a Handicap. In combat, the moment the target has been affected by a Mortal wound, or higher, you may immediately pull and play an additional Ordeal card.','Nimbed_Reward'=>'Clips, (Gain Sin Nimbed Boon Reduced Chi).','Nimbed_Trick'=>'Addictive for the Target, they enjoy the effect and want more regardless of damage that the Annex may cause (After the first use, all additional uses gain Sin Nimbed Boon Reduced Pips of Penetration).', 'Umbral_Limit'=>'Cannot be used to do good or Halve Score.','Umbral_Need'=>'Pain, will only activate if Wounds of Pips equivalent to Annex Boon Reduced are present in the Scene.','Umbral_Sacrifice'=>'Clips, after a limited number of uses must consume a Prop of Cost equal to at least Annex Boon Double Reduced + Sin Umbral Boon Reduced. Base number of Uses is 27-Sin Umbral Boon. Refs may allow larger clips that cost proportionally more.','Umbral_Special'=>'Addictive for the user and must be use Sin Umbral Boon Reduced times a day or it operates at Half score until you achieve your uses per day again.'),
	array('Annex_Channel'=>'Attacks / Metal / Cybernetics / Hacking','Annex_Root'=>'Warfare / Sport / Competition / Attacking','Nimbed_Expand'=>'Any time the Annex Wounds a Target (or their Descendants) immediately pull and play an additional Card.','Nimbed_Focus'=>'Competition, any time you can match an Ordeal card played against you in Pips you may Draw and Play an additional card.','Nimbed_Reward'=>'Peace of mind, (Gain Trial Nimbed Boon Chi if the Annex succeeds).','Nimbed_Trick'=>'Spades Flush, anytime the Annex plays more than one Spade all Spades are one Level higher.','Umbral_Limit'=>'Others...Halve Score when User is the Target.','Umbral_Need'=>'Competition, will only activate if the Target is equivalent in Scale or higher.','Umbral_Sacrifice'=>'Peace of mind, (Trial Umbral Boon Reduced Yang).','Umbral_Special'=>'Automatically wounds the Annex holder (User or Descendant). Trial Umbral Boon Reduced and multiplied by two gives the face value of the wound type required. e.g. 1-7 Distract, 8-11 Flesh, 12-15 Maim, 16-20 Crippling, 21-25 Mortal, 26 Carnage.'),
	array('Annex_Channel'=>'Energy / Holy / Saintly','Annex_Root'=>'Virtue / Moral / Ethical','Nimbed_Expand'=>'The Virtue Boon Reduced may be added to the Annex&#39;s score when taking the average, helping another, or against defences.','Nimbed_Focus'=>'Beam, the Annex creates a narrow beam, anyone caught in the Beam counts as a potential Target. Draw one card and play it for Extra Targets (+3 each). The Beam will stop after the Extra Targets are paid for.','Nimbed_Reward'=>'Prayers, Annex may once per Story Miracle a test or increase all Ordeal cards played by the Annex to Jokers.','Nimbed_Trick'=>'All Diamond Ordeal Cards add Virtue Nimbed Boon Reduced Pips automatically when played in this Annex’s action.','Umbral_Limit'=>'Must be used to help another or Halve Score.','Umbral_Need'=>'Last resort, will only activate as a last resort.','Umbral_Sacrifice'=>'Power, (Annex Boon Double Reduced Chi) or connect to a power source.','Umbral_Special'=>'Has 27- Virtue Umbral Boon uses and then must wait Annex Boon Double Reduced as Yarn on Sway table Extend Duration before another attempt.'),
	array('Annex_Channel'=>'Magic / Law / Judgment','Annex_Root'=>'Fate / Magic / Legal','Nimbed_Expand'=>'In Liminal Spaces and Times add One Success Level','Nimbed_Focus'=>'Doom, Draw Wyrd Nimbed Boon Reduced Wyrd Tarot cards and play Wyrd Nimbed Boon Double Reduced immediately, discard the others.','Nimbed_Reward'=>'Mana (The Annex generates Wyrd Boon Double Reduced Yarn or Twists each use).','Nimbed_Trick'=>'Inevitable, if Wound cards played during the Annex&#39;s action fail to penetrate armour or defences, or if inevitable defences fail to stop a Wound, they Draw a card to replace the failed one and add Wyrd Nimbed Boon Reduced Pips.','Umbral_Limit'=>'Only works in liminal spaces and times (e.g. At midnight, dusk, dawn, in a doorway or hedge) or Halve Score','Umbral_Need'=>' Doom, must have a Wyrd Tarot hand (or Yarn Cards) with Pips equal to Annex Boon Reduced.','Umbral_Sacrifice'=>'Mana (Annex Boon Double Reduced Chi).','Umbral_Special'=>'All recent effects created by the Annex (Ref decides how recently) are instantly undone if the Annex is Crippled for any reason. E.g. A wizard that loses their Wizardry will lose his magical buffs and may even lose his summoned familiar or tower.'),
	array('Annex_Channel'=>'Range / Reach / Space / Location','Annex_Root'=>'Location / Space / Alien','Nimbed_Expand'=>'As long as the Annex does not Physically affect the Target it may effectively ignore costs for Range. Referees may arbitrate, an ideal Nimbed for Communication Powers.','Nimbed_Focus'=>'Add Yonder Nimbed Boon Reduced Pips to any attack at range.','Nimbed_Reward'=>'Focus (Gain Yonder Boon Reduced Chi)','Nimbed_Trick'=>'Yonder Boon divides Range before difficulty is calculated. Confined is divided by Yonder Boon Reduced, Closed by Yonder Boon and Open by Yonder Value. e.g. Boon 2=1/2/ 5 divides distance by 1 when Confined, 2 Closed and 5 when Open, where as Boon 13=4/13/66','Umbral_Limit'=>'Must be at a minimum Range of Annex Boon Reduced metres or Halve Score.','Umbral_Need'=>'Space, a Location of size greater than the Annex Boon Double Reduced as Yarn.','Umbral_Sacrifice'=>'Focus (Yonder Umbral Boon Reduced Yin).','Umbral_Special'=>'Range is multiplied by 1+ Yonder Umbral Boon Reduced before calculation.'),
	array('Annex_Channel'=>'Motion / Vehicles / Change','Annex_Root'=>'Faith / Belief / Travel','Nimbed_Expand'=>'Powerful, Add Zeal Nimbed Boon Reduced to the Annex Boon.','Nimbed_Focus'=>'The Annex recovers rapidly, take Zeal Nimbed Boon Reduced from the Annex RT to a minimum of the normal GRT of that Annex, and take Zeal Nimbed Boon Double Reduced from GRT (to a minimum of 0).','Nimbed_Reward'=>'Motion, Annex causes Motion in either the User or Target equal to Zeal Nimbed Boon metres for small Objects and Zeal Boon Reduced metres for Characters or larger. ','Nimbed_Trick'=>'The user of the Annex is completely immune to the effects of the Annex, even fumbles, bounced attacks or stolen Annexes cannot affect them.','Umbral_Limit'=>'Must be used after another Annex has been used in the Round (or at the same time as another Annex when rolling), or Halve Score.','Umbral_Need'=>'Triggered Handicap, of Boon at least equal to Annex Boon Double Reduced','Umbral_Sacrifice'=>'Motion, must move Annex Boon Reduced metres to Activate.','Umbral_Special'=>'Effects are illusory or can be disbelieved. Targets can use Personality Annex to passively Defend or Soak.')));
