array('Type'=>'Skill', 'Description'=>'The simplest Annex Type made from just 2 Proficiencies. A Character may have as many Skills as their highest Handicaps Banes.', 'Prof_Slots'=>'2', 'Char_Slots'=>'Largest Handicap Reduced'),
array('Type'=>'Talent', 'Description'=>'When you add a Proficiency to a Skill you add an Umbral to the Skill and create a Talent. More poweful than a Skill, but more restricted too. Talents may have as many Proficiencies as their Number of Handicaps Reduced.', 'Prof_Slots'=>'3', 'Char_Slots'=>'1 per Skill' ),
array('Type'=>'Power', 'Description'=>'When you improve a Talent by adding enough Proficiencies it becomes a Power. Powers can have as many Umbral and Nimbeds as the Character has Handicaps.', 'Prof_Slots'=>'3',  'Char_Slots'=>'Number of Talents Reduced.'),
array('Type'=>'Super-Skill', 'Description'=>'Solos and Grand Mercari may promote any one Annex to being a Super-Skill. Super-Skills are available to all Alternates. Super-Skills add the Boons of their Root and Channel together directly (adding any Umbral Values normally) and gain Proficiencies to fill all Nimbed Slots for both Root and Channel, (while keeping all other Umbrals and Nimbeds)', 'Prof_Slots'=>'10', 'Char_Slots'=>'1'),
array('Type'=>'Skill (Bonus)', 'Description'=>'A Bonus Skill, granted either by a Core or a Monolith or Artefact.', 'Prof_Slots'=>'2', 'Char_Slots'=>'There is no limit to the number of bonuses a Character may have.'),
