array('Type'=>'Power (Bonus)', 'Description'=>'A Bonus Power, granted by a Core, Monolith or Artefact.', 'Prof_Slots'=>'3', 'Char_Slots'=>'There is no limit applied to Bonus Powers for Characters.'),
array('Type'=>'Super-Skill (Bonus)', 'Description'=>'A Bonus Super-Skill usually granted by an Artefact.', 'Prof_Slots'=>'10', 'Char_Slots'=>'There is no direct limit to the number of Bonus Super-Skills a Character may have, although there are limits on the number of Artefacts that they may own.')));
