		$col[]=array('Name'=>'Description', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'altt-description', 'Tooltip'=>'How is this persona different to the rest of the Character?');
		$this->AddTable($package,"Alternate_Types",$col, 'Type', '', array('Description'=>'In T13 Characters rarely are just who they think they are. Past (and future) lives, secret identities, multiple personality disorders and quantum shenanigans all have their parts to play.','Tooltip'=>'Alternate Types', 'HelpText'=>'Choose a Type for your Alternate', 'Code'=>'Open', 'ContainerPost'=>FALSE, 'DisplayRow'=>'<details data-level="%level%" data-help="%tab-help%" data-tooltip="%tab-tooltip%" ><summary class="altt-type">%Type%</summary><p class="altt-description">%Description%</p></details>','Template'=>''), array(   		 
array('Type'=>'Nominative', 'Description'=>'We are all different people to different people. This alternate is perhaps just that Character you were in Primary School, you know when you had THAT nickname.'),
array('Type'=>'Personality Disorder', 'Description'=>'Sometimes the inner monolgue in a Character&#39;s head start using different voices. Madness, Paranoia and mentally Scarred Handicaps can even create these Alternates.'),
array('Type'=>'Past-Life', 'Description'=>'A simple to understand Alternate. Especially common amongst the Fields of the Herd Bulmäs, who collect chains of linked past-lives, and recognise Soul-Siblings as those who shared a Soul in a Past-life (they share Alternates).'),
