		$col[]=array('Name'=>'Description', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'st-description', 'Tooltip'=>'How Similar to the original Persona is this Alternate one?');
		$this->AddTable($package,"Similarity_Types",$col, 'Type', '', array('Description'=>'How Similar is this Alternate to the Primary?','Tooltip'=>'Alternate Types', 'HelpText'=>'Choose a Similarity for your Alternate', 'Code'=>'Open', 'ContainerPost'=>FALSE, 'DisplayRow'=>'<details data-level="%level%" data-help="%tab-help%" data-tooltip="%tab-tooltip%" ><summary class="st-type">%Type%</summary><p class="st-description">%Description%</p></details>'), array( 
array('Type'=>'Same', 'Description'=>'The Alternates are essentially identical. They have the same personality, core, handicaps and annexes, but might differ in Geometry, or a few Proficiencies. Most Nominative Alternates are this (only differing in the Geometry — and sometimes not even in that), and some Quantum Alternates too. These Alternates normally automatically Coalesce with the character, although the character can get half of their Chi back from adding a personality if they make the new Alternate Integrated (or Co-dominant or Split) instead.'),
array('Type'=>'Similar', 'Description'=>'This Alternate is similar to the original character, they have the same Facet Boons, but the alternate may swap around Personality, Core and Handicaps to create a new Personality with exactly the same Personality Boon, the alternate Personality usually has different Annexes. Most Quantum Alternates fall into this type, and some Past-Life ones as well. These Personalities are often Integrated when first created, but the character can get half the Chi back from adding the alternate by making the alternate personality a Co-Dominant or Split instead.'),
array('Type'=>'Related', 'Description'=>'This Alternate is radically different to the original Alternate but has connections to the original, for example both might share a Fear of Spiders Handicap. Most Past-life Alternates fall into this similarity, but many Quantum and some Possessions would qualify, as would some Personality Disorders. Such related characters usually begin as Co-dominant but can be Split instead with the Character receiving back half the Chi spent adding the Alternate.'),
array('Type'=>'Unrelated', "Description"=>'This personality has nothing (or very little) in common with the original character. They are completely different entities who are blended together unfortunately. Disorders and Posession Alternates are usually about this similar, but more than a few Mercari or Bulmäs have picked up these kinds of Alternates. It is normal for unrelated personalities to be Split.')));
