		$this->addHandicap('Nasty (Specify)','Nasty Handicaps are the Offensive Handicap that you can give almost any evil Character. It can describe everything from sharp-tongued scold to a vile prison torturer, and everything in between.',18, 1, 3, true,true,10,1);
		$this->addHandicap('Profane (Specify)','The Profane Handicap is intended for those Characters who a little bit unsacred. They might be atheists in a religious country, or just be as common as muck.',18, 1, 4, true,true,1,10);
		$this->addHandicap('Ugly (Specify)','The Ugly Handicap is a unique Offensive Handicap, it can just be that the Handicap makes someone or something Ugly on the outside, but more often Ugliness is not skin deep.',18, 1, 5, true,true,10,1);
		$this->addHandicap('Prejudiced (Specify)','The Prejudiced Handicap simplyu means that a Character has certain (specified) classes of people and things that they constantly pre-judge, deciding things about others based on their skin tone, genitals or number of tentacles.',18, 1, 6, true,true,10,1);
