		$this->addHandicap('Irritable (Specify)','The most common of the Defensive Handicaps is the Irritable Handicap, almost any Character can be irritable, especially if you specify when tired.',20, 1, 3, true,true,10,1);
		$this->addHandicap('Vigilant (Specify)','Vigilant Handicaps seem at first to not be a Handicap, but you wait until you have been up for three days, and still can not bring yourself to sleep while alien invaders creep around outside.',20, 1, 4, true,true,10,1);
		$this->addHandicap('Hypersensitive (Specify)','The Hypersensitive Handicap is, if some are to be believed, the choice of the next generation. Hypersensitive Characters are easily triggered by specified events, behaviours or substances. A Hypersenstivity to noise might send need a Character to wear earplugs for a normal life, etc.',20, 1, 5, true,true,10,1);
