		$this->addHandicap('Uncaring (Specific)','For some they Apathy Handicap indicates that they are simply Uncaring. They may be aloof, or mean, or simply robotic. Being Uncaring can cause harm to themselves as they are injured by feelings.',21, 1, 1, true,true,10,1);
		$this->addHandicap('Disspassionate (Specific)','Dispassionate Characters never really get into anything. They may lack emotions, or a specific one, or simply be easily bored.',21, 1, 2, true,true,10,1);
