		$this->addHandicap('Rapture (Specify)','Rapture Handicaps are intended to mimic Characters who are just incapable of soing much. They might be a blissed out drug user, or be a Comatose victim of an illness or wound, they might even just be a happily settled old warrior who doesn&#39;t want to stir up any trouble.',21, 1, 4, true,true,10,1);
