		$this->addHandicap('Star-crossed (Specify)','Sometimes fate and the Wyrd have nothing good planned for a Character. Perhaps its a cursed love-life, or ill-luck with money, or bad health. No matter what could happen, it always seems to turn out badly for a Star-crosssed Handicap.',22, 1, 3, true,true,10,1);
