	$col[]=array('Name'=>'Type', 'Type'=>'VARCHAR(32)', 'Edit'=>'<input type="text" value="%s" maxlength="32"/>', 'Display'=>'<span>', 'CSS'=>'type-table-type', 'Tooltip'=>'Type');
	$col[]=array('Name'=>'Sway_Type_Description', 'Type'=>'MEDIUMTEXT', 'Edit'=>'<textarea>%s</textarea>', 'Display'=>'<p>', 'CSS'=>'sway-type-description', 'Tooltip'=>'Description');
	$this->AddTable($package,"Type_Sway_Table",$col, array('Chi','Element_Type', 'Type'), array(array('LocalCol'=>'Chi', 'Table'=>'Sway_Table', 'ForCol'=>'Chi')), array('Description'=>'Extends the Sway Table.','Tooltip'=>'Sway Table Types', 'HelpText'=>'The Sway Table Type columns.', 'Code'=>'Direct', 'ContainerPost'=>FALSE, 'DisplayRow'=>'<details open><summary><strong>Type: </strong><span class="type-table-type">%Type%</span></summary><p><strong>Element Type: </strong><span class="type-table-element">%Element_Type%</span></p><p><strong>Chi: </strong><span class="type-table-chi">%Chi%</span></p><p><strong>Description: </strong><span class="sway-type-description">%Sway_Type_Description%</span></details>','Template'=>''), array(
		array('Chi'=>'1','Element_Type'=>'Annex','Type'=>'Proficiency','Sway_Type_Description'=>'A Proficiency is a unit of knowledge. It may be a single memory, or it might have come from years of dedicated research or training. Proficiencies can really, describe anything. Even Annexes built from multiple Proficiencies will also have a single Proficiency in their use.'),
		array('Chi'=>'1','Element_Type'=>'Rules','Type'=>'Reroll','Sway_Type_Description'=>'You can reroll any single diceroll. You may use either score.'),
		array('Chi'=>'1','Element_Type'=>'Technology','Type'=>'Primitive','Sway_Type_Description'=>'Primitive technologies include simple machines (such as the wedge, lever, and screw), ropes, knots, stones, wood, animal prodicts, water, and fire starting.  '),
		array('Chi'=>'2','Element_Type'=>'Annexes','Type'=>'Skill','Sway_Type_Description'=>'A Skill based Annex, made from two Proficiencies.'),
		array('Chi'=>'2','Element_Type'=>'Descendants','Type'=>'Skill','Sway_Type_Description'=>'A Skill based Descendant.'),
		array('Chi'=>'2','Element_Type'=>'Characters','Type'=>'Vex (Extra)','Sway_Type_Description'=>'Any NPC created with a single Skill Annex.'),
		array('Chi'=>'2','Element_Type'=>'Technology','Type'=>'Animal Husbandry','Sway_Type_Description'=>'This technology arrived quite early and allowed human beings to tame wild animals, making them more suitable for human needs. This includes domestication, training and animal breeding in one Technology.'),
		array('Chi'=>'3','Element_Type'=>'Technology','Type'=>'Farming','Sway_Type_Description'=>'Farming Technology includes all sorts of land and crop management techniques. Specific tools may be developed to assist in planting or harvesting. Digging, mining and irrigation techniques become common. Wall and fence building for animal pens leads to creation of homes and villages. Civilization is on the way.'),
		array('Chi'=>'4','Element_Type'=>'Technology','Type'=>'Energy Storage','Sway_Type_Description'=>'Simple energy Storage technology includes the ability to convert Energy from one type to another, typically from kinetic energy to mechanical potential energy to kinetic energy (The Bow and Arrow).'),
		array('Chi'=>'5','Element_Type'=>'Annexes','Type'=>'Talent','Sway_Type_Description'=>'A Talent based Annex.'),
		array('Chi'=>'5','Element_Type'=>'Descendants','Type'=>'Talent','Sway_Type_Description'=>'A Talent based  Descendant.'),
		array('Chi'=>'5','Element_Type'=>'Characters','Type'=>'Chorus (Extra)','Sway_Type_Description'=>'Any NPC created with a Talent Annex. These are the guys that fill the background of any scene.'),
		array('Chi'=>'5','Element_Type'=>'Technology','Type'=>'Primitive Chemistry','Sway_Type_Description'=>'Understanding of materials is developed that includes metallurgy. Alloying and simple chemistry are developed.'),
		array('Chi'=>'6','Element_Type'=>'Technology','Type'=>'Mechanics','Sway_Type_Description'=>'Mechanical Technology allows everything from clocks to aeroplanes. Although you might be looking at fairly primitive versions of both to start with.'),
		array('Chi'=>'7','Element_Type'=>'Annexes','Type'=>'Power','Sway_Type_Description'=>'A Power based Annex or Descendant.'),
		array('Chi'=>'7','Element_Type'=>'Descendants','Type'=>'Power','Sway_Type_Description'=>'A Power based Descendant.'),
		array('Chi'=>'7','Element_Type'=>'Characters','Type'=>'Cast (Extra)','Sway_Type_Description'=>'Any NPC created with a Power Annex. The Cast of a Story are those Named Characters that aren\'t quite worth making a Grunt for.'),
		array('Chi'=>'7','Element_Type'=>'Rules','Type'=>'Redraw','Sway_Type_Description'=>'Discard and Redraw a single card from your Hand or Pool.'),
		array('Chi'=>'8','Element_Type'=>'Characters','Type'=>'Grunt','Sway_Type_Description'=>'The simplest true Character. They are Full Characters in the system, but don\'t have access to the Edges and abilities of Mercari and other Types.'),
		array('Chi'=>'8','Element_Type'=>'Descendants','Type'=>'Trophy','Sway_Type_Description'=>'Trophies are the simplest of the special descendants. They are an ordinary Descendant that has extra Yin or Yang Sway stored within it.'),
		array('Chi'=>'8','Element_Type'=>'Events','Type'=>'Chronolith','Sway_Type_Description'=>'Chronoliths are events, moments, infused with additional Chi to make them more histrorically certain than usual. Mercari can utilise and manipulate Chronoliths in unusual ways.'),
		array('Chi'=>'8','Element_Type'=>'Characters','Type'=>'Bulmäs Child','Sway_Type_Description'=>'The youngest of the Bulmas, they are usually called cubs or calves, depending upon the path they walk. Bulmäs Children have only their own original soul and cannot walk the Lea until they receive a travelling soul.'),
		array('Chi'=>'9','Element_Type'=>'Technology','Type'=>'Chemistry','Sway_Type_Description'=>'An advanced understanding of Chemistry allows the synthesis of new materials, it also allows specific elements such as silicon and germanium to be discovered.'),
		array('Chi'=>'10','Element_Type'=>'Technology','Type'=>'Electrics','Sway_Type_Description'=>'Electricity is a primitive harnessing of the electron. Initially power levels are low, based on DC batteries, and it might take years to work out how to convert it efficiently into other forms of energy, but it unlocks a lot of potential.'),
		array('Chi'=>'12','Element_Type'=>'Annexes','Type'=>'Super-Skill','Sway_Type_Description'=>'A Super-Skill based Annex.'),
		array('Chi'=>'12','Element_Type'=>'Descendants','Type'=>'Super-Skill','Sway_Type_Description'=>'A Super-Skill based Descendant.'),
		array('Chi'=>'12','Element_Type'=>'Characters','Type'=>'Neechies','Sway_Type_Description'=>'The least powerful of the Increated, Neechies are the movement you catch from the corner of your eye, generally Harmless unless they find a Nightmare Fuel source...'),
		array('Chi'=>'12','Element_Type'=>'Characters','Type'=>'Force-of-Nature (Extra)','Sway_Type_Description'=>'Any NPC created with a Super-Skill Annex.'),
		array('Chi'=>'12','Element_Type'=>'Characters','Type'=>'Mercari','Sway_Type_Description'=>'The Fae call them Mercari, but humans call them things like Demi-gods, Superstars and Heroes. The Bulmäs usually refer to Mecari as having Souls (if not True Souls or Great Souls), although they also use the term Wyrd-Childe for these beings. Mercari have the ability to Trade their destinies and manipulate reality.'),
		array('Chi'=>'12','Element_Type'=>'Characters','Type'=>'Goblin','Sway_Type_Description'=>'Goblins are Grunts with access to Twists, usually as result of a Woe Handicap (or two).'),
		array('Chi'=>'12','Element_Type'=>'Descendants','Type'=>'Monolith','Sway_Type_Description'=>'Monoliths are Descendants imbued with additional Edges and abilities by a Mercari (or similar) storing Chi within them.'),
		array('Chi'=>'12','Element_Type'=>'Descendants','Type'=>'Location','Sway_Type_Description'=>'Locations are a special type of Descendant that models a place in the Game, or Story.'),
		array('Chi'=>'12','Element_Type'=>'Descendants','Type'=>'Monolith','Sway_Type_Description'=>'Monoliths are Descendants imbued with additional Edges and abilities by a Mercari (or similar) storing Chi within them.'),
		array('Chi'=>'12','Element_Type'=>'Characters','Type'=>'Bulmäs Adult','Sway_Type_Description'=>'Bulmas Herd or Hunters are able to walk the Lea and shape change.'),
		array('Chi'=>'13','Element_Type'=>'Technology','Type'=>'Electronics','Sway_Type_Description'=>'Advanced Electronics, let electricity become a control system, decision making, calculating.'),
		array('Chi'=>'15','Element_Type'=>'Technology','Type'=>'Nuclear','Sway_Type_Description'=>'These Technologies allow exploitation of the inherent energy in matter, specifically the radiation caused by matter loss in radioactive isotopes. Harnessed correctly these can make clean, long-lasting powersources. Also bombs.'),
		array('Chi'=>'16','Element_Type'=>'Characters','Type'=>'Demon','Sway_Type_Description'=>'Mercari that have at least one Woe Handicap are called Demons. They can generate and use Twists to subvert the Narrative.'),
		array('Chi'=>'16','Element_Type'=>'Characters','Type'=>'Daemon','Sway_Type_Description'=>'The Rank and File of the Increated, devious and desperate for existence these Increated usually have experience of the real world and understand how to cultivate the Nightmare Fuel Twists that they desire.'),
		array('Chi'=>'16','Element_Type'=>'Descendants','Type'=>'Pact Descendant','Sway_Type_Description'=>'When a Descendant represents a group of people we call it a Pact Descendant. Pact Descendants can be as small as a pair of individuals or larger than the human race.'),
		array('Chi'=>'16','Element_Type'=>'Descendants','Type'=>'Real Estate','Sway_Type_Description'=>'Real Estate is what we call a Monolithed Location. Real Estate have different Edges to ordinary Monoliths.'),
		array('Chi'=>'16','Element_Type'=>'Characters','Type'=>'Fae Commonner','Sway_Type_Description'=>'The Commoners of the the Fair folk.'),
		array('Chi'=>'16','Element_Type'=>'Characters','Type'=>'Bulmäs Adult Broccen','Sway_Type_Description'=>'Adults of the Broccen Bulmas can walk any of the Lea Paths. They are omnivores themselves, and keep territory, they do not migrate from place to place. Broccen are also capable of creating new Lea Paths, which also creates a new creature to fill the niche if there is none available. Broccen are also capable of partial transformations.'),
		array('Chi'=>'17','Element_Type'=>'Technology','Type'=>'Biotechnology','Sway_Type_Description'=>'Biochemistry and Biology combine with engineering to allow life to be restructed to our needs. '),
		array('Chi'=>'20','Element_Type'=>'Technology','Type'=>'Nanotechnology','Sway_Type_Description'=>'Programmable Matter, a shape-shifting, Physical Technology that can even infiltrate and improve biological systems, creating things like Neural Computer Interfaces, Ballistic Dermal Armour, and laser eyeballs. Initially the technology is primitive and error prone.'),
		array('Chi'=>'21','Element_Type'=>'Characters','Type'=>'Grand Mercari','Sway_Type_Description'=>'Mercari that have accumulated multiple Alternate personalities are able to manipulate reality in ways that go beyond even the simple Wyrd Tarot abilities of the Mercari. Grand Mercari can manipulate Yarn directly.'),
		array('Chi'=>'21','Element_Type'=>'Characters','Type'=>'Solo','Sway_Type_Description'=>'A special type of Grand Mercari where all their Alternates are completely integrated. Solos are always themselves in any universe that you may encounter them.'),
		array('Chi'=>'21','Element_Type'=>'Descendants','Type'=>'Province','Sway_Type_Description'=>'Locations that have been imbued with Yarn directly are like Real Estate, turned up to 11. They have multiple Edges and additional abilities that grant their owners a number of advantages.'),
		array('Chi'=>'21','Element_Type'=>'Characters','Type'=>'Bulmäs Vermis','Sway_Type_Description'=>'Vermis is the Bulmäs lord of the dead, and is a Solo. Every Vermis Bulmäs is an aspect of Lord Vermis himself, although recently they have begun to differentiate themselves from each other somewhat. Vermis Bulmäs have a Draconic form that they use for harvesting all the Bulmäs Souls from a world.'),
		array('Chi'=>'21','Element_Type'=>'Descendants','Type'=>'Artefact','Sway_Type_Description'=>'A Descendant granted Yarn by A Plot Demon or Grand Mercari is called an Artefact and has a lot of Edges and grants it\'s weilder special abilities.'),
		array('Chi'=>'21','Element_Type'=>'Characters','Type'=>'Inactive Alternate','Sway_Type_Description'=>'Trying to affect the Personality of any Character\'s Alternates in another universe, is as hard as affecting them as it can get.'),
		array('Chi'=>'21','Element_Type'=>'Characters','Type'=>'Eelafin / Fae Hybrid','Sway_Type_Description'=>'A blending of mortal and immortal beings, the Eelafin are a particular example of Faery Mortal Hybrid.'),
		array('Chi'=>'25','Element_Type'=>'Technology','Type'=>'Moving Holograms','Sway_Type_Description'=>'Maniuplation of coherent laser light, and simliar technologies allows the construction of free standing projected three dimensional images.'),
		array('Chi'=>'26','Element_Type'=>'Characters','Type'=>'Demonlord','Sway_Type_Description'=>'When Grand Mercari have a Woe Handicap they become incredibly powerful beings known as Demonlords. Demonlords are only a step in power below the true Increated Daemon-Princes.'),
		array('Chi'=>'26','Element_Type'=>'Characters','Type'=>'Fae Noble','Sway_Type_Description'=>'The most powerful members of Faery society are called the Fae Nobles. The most powerful of those Nobles are always Doomweavers of some sort.'),
		array('Chi'=>'26','Element_Type'=>'Characters','Type'=>'Bulmäs Labyrinthine','Sway_Type_Description'=>'The most powerful members of Bulmäs society are the so-called Lost Souls. They live in the knotted Lea that most Bulmäs ignore and avoid, which also coincidently is knotted by the human path. The Labyrinth is the Lea of Urban environments.'),
		array('Chi'=>'26','Element_Type'=>'Characters','Type'=>'Fae Noble','Sway_Type_Description'=>'The most powerful members of Faery society are called the Fae Nobles. The most powerful of those Nobles are always Doomweavers of some sort.'),
		array('Chi'=>'30','Element_Type'=>'Technology','Type'=>'Force-fields','Sway_Type_Description'=>'Sonic and energy manipulation allows the construction of solid feeling force-fields. Advanced forms of the technology can even function in vacuum, creating solid planes of force from manipulations of the Higgs field, or restructuring electrons and photons via tuned quantum resonance.'),
		array('Chi'=>'32','Element_Type'=>'Characters','Type'=>'Battle Toon','Sway_Type_Description'=>'Crafted from force-fields and holographic Technology originally, Battle Toons are adaptable chaotic battle engines that can mess up any carefully laid plans of any general.'),array('Chi'=>'38','Element_Type'=>'Characters','Type'=>'Immortal','Sway_Type_Description'=>'Unaging, even undying beings that look human, but are far from it.'),
		array('Chi'=>'40','Element_Type'=>'Technology','Type'=>'Artificial Gravity','Sway_Type_Description'=>'This lets you have people walking around on spaceships. It also lets you have thrusterless hovering "anti-gravity" vehicles.'),
		array('Chi'=>'45','Element_Type'=>'Characters','Type'=>'Monster','Sway_Type_Description'=>'Monsters are amongst the most power types of Characters because they can be any other Character Type with Monster Facets.'),
		array('Chi'=>'51','Element_Type'=>'Characters','Type'=>'Eternal','Sway_Type_Description'=>'The most powerful Immortal Solos are known as Eternals.'),
		array('Chi'=>'59','Element_Type'=>'Characters','Type'=>'Kaiju','Sway_Type_Description'=>'Enormous Monsters that are, at least initially, built from a Location Descendant with a suitably large Size Annex. Typically destroy famous world monuments, may trash Tokyo or New York, your results may vary.'),
		array('Chi'=>'60','Element_Type'=>'Technology','Type'=>'Space Warping','Sway_Type_Description'=>'Careful manipulation of energy fields lets this technology warp space (at least in a basic way similar to gravity.) This allows interplanetary travel at relativistic speeds (and possibly a smidge faster).'),
		array('Chi'=>'66','Element_Type'=>'Characters','Type'=>'Paragon','Sway_Type_Description'=>'Any Character that reaches Scale 13 is known as a Paragon of its type. Paragons may always roll dice or draw cards twice and keep whichever they prefer (usually the highest). Cards should be dealt to them in pairs and they may choose between them, automatically discarding the alternate.'),
		array('Chi'=>'83','Element_Type'=>'Plots','Type'=>'Scene Demon','Sway_Type_Description'=>'The least powerful of the Narrative Demons. Plot Demons are of the Increated, they were created by mankind as a byproduct of trying to make sense of the Omniverse.'),
		array('Chi'=>'92','Element_Type'=>'Plots','Type'=>'Act Demon','Sway_Type_Description'=>'Act Demons organize Scene Demons to marshal them for the Story.'),
		array('Chi'=>'101','Element_Type'=>'Plots','Type'=>'Short Story Demon','Sway_Type_Description'=>'Story Demons examine a Conflict to tell a single Story, with limited Characters and Locations.'),
		array('Chi'=>'111','Element_Type'=>'Plots','Type'=>'Story Demon','Sway_Type_Description'=>'Story Demons examine a Conflict to tell a Story, usually as part of a larger Arc.'),
		array('Chi'=>'120','Element_Type'=>'Technology','Type'=>'Wormhole Technology','Sway_Type_Description'=>'This technology allows Space-Time to be manipulated into creating a Wormhole that will allow travel from one point in space-time to another. This technology can usually only allow transmission of information through the wormhole. Projecting matter requires additional exotic forms of energy and matter that are harder to synthesise.'),
		array('Chi'=>'121','Element_Type'=>'Characters','Type'=>'Lesser Divinties','Sway_Type_Description'=>'The Lesser Divinities are the greatest, most powerful of spirits. They are also known as Angels, Small Gods, Nephilim and Great Spirits, amongst other things. They are impressive individuals of great age, that are imprinted upon the operating system of the universe. They are tasked with guarding and guiding groups and important individuals according to the Wyrd\'s memories of the future. Lesser Divinities are usually immune to Sway based effects (including Facet or Annex based Dice roll Scores, Ordeal card Pips, Wound Daemons, and Wyrd Tarot effects - except where Handicaps, Annnex Umbrals or Nimbeds, or I-Ching may interfere). They can be affected by Yarn and Twists, and many are affected by Chi based effects (although not all).'),
		array('Chi'=>'142','Element_Type'=>'Technology','Type'=>'Femite technology','Sway_Type_Description'=>'Programmable Matter not smart enough for you? How about programmable particles. Electrons that carry tech inside them. Femite technology is created by Magic not strictly speaking Science.'),
		array('Chi'=>'153','Element_Type'=>'Technology','Type'=>'Baryonite technology','Sway_Type_Description'=>'Programmable Neutrons and Protons, the ultimate in Programmable matter. Create unbreakable, weird materials from Comicbooks, extract information from Quark Soup and Quantum Foam.'),
		array('Chi'=>'165','Element_Type'=>'Plot','Type'=>'Arc Demon','Sway_Type_Description'=>'Arc Demons organize Story Demons into Plot Arcs.'),
		array('Chi'=>'177','Element_Type'=>'Plot','Type'=>'Volume Demon','Sway_Type_Description'=>'Volume Demons organize Arc Demons into Volumes, which are about a Novels worth...'),
		array('Chi'=>'190','Element_Type'=>'Plot','Type'=>'Epic Demon','Sway_Type_Description'=>'Epic Demons organize Volumes Demons into longer series.'),
		array('Chi'=>'216','Element_Type'=>'Characters','Type'=>'Gods','Sway_Type_Description'=>'They might be divine beings, or the ultimate in Toon technology, no one is really sure if there\'s a real difference anymore. They are completely immune to all but the largest Twist and Yarn based effects. Sway in any form and Chi simply cannot effect them, unless they choose, and exert effort in letting it. Gods usually patronise some aspect of the society that worships their Pantheon. These Patron Annexes are always created as a Super-Skill (and Gods may have more than one) "Godhead" Lore Descendant, they can be lost, transferred, and gifted.'),
		array('Chi'=>'230','Element_Type'=>'Technology','Type'=>'Multiversal Connection','Sway_Type_Description'=>'Contact other universes, and share information with them. Possibly even travel there.'),
		array('Chi'=>'259','Element_Type'=>'Plot','Type'=>'Cycle Demon / Patron Demon','Sway_Type_Description'=>'The greatest of the grand plots. Hold entire Multiverse together. Or rule Shades and try and conquer the Omniverse...'),
		array('Chi'=>'259','Element_Type'=>'Characters','Type'=>'Secondary Anomaly','Sway_Type_Description'=>'Secondary Anomalies are the Great Gods. These Divine beings carry echoes of the Prime Anomaly, which is why in their universe they are considered Creator Gods. They usually lead pantheons or councils of gods, or establish Monotheistic religions, with Lesser Divininties filling the roles of the other gods.'),array('Chi'=>'274','Element_Type'=>'Technology','Type'=>'Nullites','Sway_Type_Description'=>'Programmable Light (and Tachyons), which may or may not be how magic and Gods work...'),
		array('Chi'=>'321','Element_Type'=>'Characters','Type'=>'Prime Anomaly/','Sway_Type_Description'=>'The original paradox that creates the whole Omniverse, and later herself. (See the Paradox War Trilogy)'))); 

